export const CARDS = [{"cat": "PCOS & Screening (Open Evidence)", "q": "Was sind die Rotterdam-Kriterien für PCOS?", "a": "Mindestens 2 von 3 Kriterien: (1) klinische/biochemische Hyperandrogenismus, (2) Ovulationsstörung, (3) polyzystische Ovarien im Ultraschall oder erhöhtes AMH. Ausschluss anderer Ursachen erforderlich.", "id": 1}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Welche Erstlinientherapie wird bei PCOS mit Menstruationsstörungen empfohlen?", "a": "Kombinierte orale Kontrazeptiva (KOK) sind Erstlinientherapie für Menstruationsunregelmäßigkeiten und Hyperandrogenismus bei PCOS.", "id": 2}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Welches Medikament ist Erstlinie für Ovulationsinduktion bei PCOS?", "a": "Letrozol ist das bevorzugte Medikament zur Ovulationsinduktion bei PCOS-Patientinnen mit Kinderwunsch.", "id": 3}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Welche metabolischen Komplikationen sind bei PCOS erhöht?", "a": "Insulinresistenz, Typ-2-Diabetes, Dyslipidämie, kardiovaskuläre Erkrankungen, obstruktive Schlafapnoe und erhöhtes Endometriumkarzinom-Risiko.", "id": 4}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Welche psychischen Komorbiditäten sollten bei PCOS gescreent werden?", "a": "Depression und Angststörungen sind signifikant erhöht bei PCOS. Screening und psychologische Therapie sind bei allen PCOS-Patientinnen empfohlen.", "id": 5}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Ab welchem Alter beginnt das Zervixkarzinom-Screening in den USA (USPSTF 2024)?", "a": "21 Jahre mit Zytologie alle 3 Jahre bis 29 Jahre. Ab 30 Jahren primäres HPV-Testing alle 5 Jahre (bevorzugt).", "id": 6}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist die bevorzugte Screening-Methode für Zervixkarzinom bei 30-65-Jährigen?", "a": "Primäres HPV-Testing alle 5 Jahre ist die bevorzugte Methode. Alternativ: Ko-Testing (HPV + Zytologie) alle 5 Jahre oder Zytologie allein alle 3 Jahre.", "id": 7}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Wann kann das Zervixkarzinom-Screening beendet werden?", "a": "Mit 65 Jahren bei adäquatem vorherigem Screening ohne Hochrisiko-CIN in den letzten 25 Jahren und negativen Screening-Ergebnissen mit 60 und 65 Jahren.", "id": 8}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist neu in den 2025 HRSA Zervixkarzinom-Screening-Leitlinien?", "a": "Selbstentnahme von HPV-Tests ist jetzt eine akzeptable Option für Frauen 30-65 Jahre. Primäres HPV-Testing alle 5 Jahre ist bevorzugt.", "id": 9}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Welche Sensitivität hat HPV-Testing vs. Zytologie für Präkanzerosen?", "a": "HPV-Testing: >90% Sensitivität. Zytologie: 50-70% Sensitivität für die Detektion von Präkanzerosen.", "id": 10}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was sind die Hauptsymptome der Endometriose?", "a": "90% berichten Beckenschmerzen (Dysmenorrhoe, nicht-menstruelle Beckenschmerzen, Dyspareunie). 26% berichten Infertilität.", "id": 11}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Ist eine Laparoskopie für die Endometriose-Diagnose zwingend erforderlich?", "a": "Nein. Klinische Diagnose basierend auf Symptomen, körperlicher Untersuchung und Bildgebung (TVUS/MRT) ist ausreichend. Empirische Therapie kann ohne chirurgische Bestätigung begonnen werden.", "id": 12}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Welche Bildgebung ist bevorzugt bei Verdacht auf tief infiltrierende Endometriose?", "a": "MRT ist bevorzugt bei Verdacht auf tief infiltrierende Endometriose. Transvaginaler Ultraschall ist erste Wahl für gynäkologische Pathologie bei chronischen Beckenschmerzen.", "id": 13}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist die Erstlinientherapie bei Endometriose ohne aktuellen Kinderwunsch?", "a": "Hormonelle Kontrazeptiva (kombinierte orale Kontrazeptiva oder reine Gestagene) mit oder ohne NSAR. Kontinuierliche Einnahme bietet bessere Schmerzkontrolle.", "id": 14}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Wie hoch ist die Rezidivrate nach Absetzen der hormonellen Endometriose-Therapie?", "a": "25-34% der Patientinnen erleben rezidivierende Beckenschmerzen innerhalb von 12 Monaten nach Absetzen der hormonellen Behandlung.", "id": 15}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Wann sollte eine chirurgische Therapie bei Endometriose erwogen werden?", "a": "Wenn Erstlinien-Hormontherapien ineffektiv oder kontraindiziert sind, bei großen Ovarialzysten oder tiefen Läsionen mit schweren Symptomen.", "id": 16}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was sind Zweitlinien-Hormontherapien bei Endometriose?", "a": "GnRH-Agonisten und -Antagonisten mit Add-back-Therapie. Drittlinie: Aromatasehemmer.", "id": 17}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Wie lange dauert die durchschnittliche diagnostische Verzögerung bei Endometriose?", "a": "5-12 Jahre nach Symptombeginn. Die meisten Frauen konsultieren 3 oder mehr Ärzte vor der Diagnose.", "id": 18}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist die Hauptindikation für Hormonersatztherapie (HRT) in der Menopause?", "a": "Behandlung von moderaten bis schweren vasomotorischen Symptomen (Hitzewallungen, Nachtschweiß), die belastend sind oder tägliche Aktivitäten beeinträchtigen.", "id": 19}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Welches Benefit-Risk-Verhältnis hat HRT bei Frauen 60 Jahre oder 10 Jahre nach Menopause?", "a": "Günstiges Benefit-Risk-Verhältnis für Behandlung belastender vasomotorischer Symptome und Prävention von Knochenverlust bei Frauen 60 Jahre oder 10 Jahre nach Menopausebeginn.", "id": 20}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Welche Risiken sind mit kombinierter Östrogen-Gestagen-Therapie verbunden?", "a": "Erhöhtes Risiko für venöse Thromboembolien, Schlaganfall und Brustkrebs (bei Langzeitanwendung). Risiken abhängig von Typ, Dosis, Verabreichungsweg und Dauer.", "id": 21}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Wann sollte Gestagen bei HRT hinzugefügt werden?", "a": "Bei Frauen mit intaktem Uterus muss Gestagen (Progesteron oder synthetisches Gestagen) oder Bazedoxifen mit Östrogen kombiniert werden, um Endometriumhyperplasie und -karzinom zu verhindern.", "id": 22}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was sind absolute Kontraindikationen für HRT?", "a": "Anamnese von Brustkrebs, koronarer Herzkrankheit, vorheriger venöser Thromboembolie oder Schlaganfall, aktiver Lebererkrankung, ungeklärter vaginaler Blutung.", "id": 23}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Welche HRT-Route sollte bevorzugt werden?", "a": "Transdermale Verabreichung sollte bevorzugt werden, da sie die geringsten Auswirkungen auf die Gerinnung hat.", "id": 24}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Wie lange sollte HRT angewendet werden?", "a": "Niedrigste effektive Dosis für die kürzeste Dauer entsprechend den Bedürfnissen der Patientin, mit regelmäßiger Neubewertung der Notwendigkeit.", "id": 25}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist das PALM-COEIN-System?", "a": "Klassifikationssystem für abnorme Uterusblutungen: PALM = strukturelle Ursachen (Polyp, Adenomyose, Leiomyom, Malignität), COEIN = nicht-strukturelle Ursachen (Koagulopathie, Ovulationsstörung, Endometrial, Iatrogen, Nicht klassifiziert).", "id": 26}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Wann sollte eine Endometriumbiopsie bei abnormer Uterusblutung durchgeführt werden?", "a": "Bei Patientinnen ≥45 Jahre und bei jüngeren Patientinnen mit signifikanter Anamnese von unopponierter Östrogenexposition.", "id": 27}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist die bevorzugte Bildgebung bei abnormer Uterusblutung?", "a": "Transvaginaler Ultraschall ist die bevorzugte Bildgebungsmodalität, wenn eine strukturelle Ätiologie vermutet wird oder Symptome trotz Therapie persistieren.", "id": 28}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist die effektivste Langzeit-Medikation bei starker Menstruationsblutung?", "a": "Levonorgestrel-freisetzendes Intrauterinsystem (LNG-IUS) ist die effektivste Langzeit-Medikation bei starker Menstruationsblutung.", "id": 29}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Welche Notfallinterventionen gibt es bei schwerer Uterusblutung mit Hämodynamik-Instabilität?", "a": "Uterustamponade, intravenöses Östrogen, Dilatation und Kürettage, Uterusarterienembolisation.", "id": 30}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was sind medikamentöse Optionen bei akuter abnormer Uterusblutung?", "a": "Intravenöses konjugiertes equines Östrogen, hochdosierte Östrogen-Gestagen-KOK, orale Gestagene, intravenöse Tranexamsäure.", "id": 31}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist die definitive chirurgische Behandlung bei starker Menstruationsblutung?", "a": "Hysterektomie ist die definitive Behandlung. Endometriumablation ist eine risikoärmere chirurgische Option mit ähnlicher Wirksamkeit wie LNG-IUS.", "id": 32}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was sind Erstlinien-Medikamente bei symptomatischen Uterusmyomen?", "a": "Kombinierte hormonelle Kontrazeptiva, Gestagen-haltige IUDs, Tranexamsäure (für Blutungssymptome). GnRH-Agonisten/-Antagonisten für Kurzzeittherapie.", "id": 33}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Welche GnRH-Therapie ist für Langzeitbehandlung von Myomen zugelassen?", "a": "Oraler GnRH-Antagonist (z.B. Relugolix) mit hormoneller Add-back-Therapie kann für bis zu 2 Jahre zur Behandlung von Myom-assoziierter Blutung eingesetzt werden.", "id": 34}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Wann ist Myomektomie indiziert?", "a": "Bei symptomatischen Myomen bei Patientinnen, die Uteruserhalt oder zukünftige Schwangerschaft wünschen. Beratung über Rezidivrisiko erforderlich.", "id": 35}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist Uterusarterienembolisation (UAE)?", "a": "Interventionelles Verfahren zur Behandlung von Uterusmyomen bei Patientinnen, die Uteruserhalt wünschen. Beratung über limitierte Daten zu reproduktiven Outcomes erforderlich.", "id": 36}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Wann ist Hysterektomie bei Myomen indiziert?", "a": "Definitive chirurgische Option bei Blutungs- und Bulk-Symptomen bei Patientinnen ohne zukünftigen Kinderwunsch oder die den Uterus nicht erhalten möchten. Beratung über Langzeit-Gesundheitsrisiken.", "id": 37}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist laparoskopische Radiofrequenzablation bei Myomen?", "a": "Minimal-invasive Behandlungsoption für symptomatische Myome bei Patientinnen, die Uteruserhalt wünschen. Limitierte Daten zu reproduktiven Outcomes.", "id": 38}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Welche Route sollte bei Hysterektomie wegen Myomen bevorzugt werden?", "a": "Die minimal-invasivste Route sollte bevorzugt werden. Vaginale Hysterektomie ist unter den minimal-invasiven Ansätzen bevorzugt, wenn durchführbar.", "id": 39}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist die kumulative Inzidenz von Uterusmyomen bis zum 50. Lebensjahr?", "a": "Etwa 70% bei weißen Frauen und 80% bei schwarzen Frauen bis zum 50. Lebensjahr.", "id": 40}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist das FIGO-Staging-System für Zervixkarzinom?", "a": "Klassifizierung basierend auf Tumorausdehnung: Stadium I (begrenzt auf Zervix), II (jenseits Zervix, nicht Beckenwand/unteres Vaginaldrittel), III (Beckenwand/unteres Vaginaldrittel/Hydronephrose), IV (Blase/Rektum oder Fernmetastasen).", "id": 41}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist FIGO Stadium IB1 beim Zervixkarzinom?", "a": "Invasion >5 mm Tiefe und ≤2 cm in größter Dimension, begrenzt auf die Zervix.", "id": 42}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist das neue FIGO-Staging für Endometriumkarzinom 2023?", "a": "Einführung molekularer Klassifikation: POLE-Mutation führt zu Down-Staging auf IAmPOLEmut (günstige Prognose), unabhängig von Histologie oder LVSI.", "id": 43}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist FIGO Stadium IIIC beim Ovarialkarzinom?", "a": "Makroskopische peritoneale Metastasierung jenseits des Beckens >2 cm in größter Dimension, mit oder ohne retroperitoneale Lymphknotenmetastasen.", "id": 44}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Welche Risikofaktoren gibt es für Endometriose?", "a": "Jüngeres Alter bei Menarche, kürzere Menstruationszykluslänge, niedrigerer BMI, Nulliparität, kongenitale obstruktive Müller-Anomalien.", "id": 45}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist die Prävalenz von Endometriose?", "a": "Betrifft bis zu 10% der Frauen weltweit während der reproduktiven Jahre, 9 Millionen Frauen in den USA.", "id": 46}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Welche Rolle spielt Metformin bei PCOS?", "a": "Metformin ist primär für metabolische Merkmale empfohlen und hat größere Wirksamkeit als Inositol. Nicht routinemäßig für schwangere Frauen mit PCOS empfohlen.", "id": 47}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Kann AMH zur PCOS-Diagnose verwendet werden?", "a": "Ja, seit 2023 kann AMH als Alternative zum Ultraschall für die Diagnose bei erwachsenen Frauen verwendet werden (nicht bei Adoleszenten wegen schlechter Spezifität).", "id": 48}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was sind die diagnostischen Kriterien für PCOS bei Adoleszenten?", "a": "Sowohl Hyperandrogenismus als auch Ovulationsstörung sind erforderlich. Ultraschall und AMH werden nicht empfohlen wegen schlechter Spezifität.", "id": 49}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Welche Lifestyle-Modifikationen werden bei PCOS empfohlen?", "a": "Gesunde Ernährung, Prävention von Gewichtszunahme, erhöhte körperliche Aktivität. Kein spezifisches Diät- oder Bewegungsregime hat Vorteile gegenüber anderen.", "id": 50}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist die Rolle von Spironolacton bei PCOS?", "a": "Antiandrogen als Zweitlinientherapie für Hirsutismus, wenn andere Therapien ineffektiv oder kontraindiziert sind. Muss mit Kontrazeption kombiniert werden.", "id": 51}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Welche Komplikationen sind mit Endometriose assoziiert?", "a": "Chronische Beckenschmerzen, Infertilität, Adhäsionen, Endometriome, tief infiltrierende Endometriose (Darm, Blase), erhöhte Risiken für Eierstockkrebs.", "id": 52}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist die Wirksamkeit hormoneller Therapien bei Endometriose-Schmerzen?", "a": "Hormonelle Behandlungen (KOK, Gestagene, GnRH-Agonisten) führen zu klinisch signifikanter Schmerzreduktion mit mittleren Differenzen von 13,15-17,6 Punkten (0-100 VAS) vs. Placebo.", "id": 53}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Wie viele Patientinnen sprechen nicht auf hormonelle Endometriose-Therapie an?", "a": "11-19% der Patientinnen mit Endometriose haben keine Schmerzreduktion mit hormonellen Medikamenten.", "id": 54}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist die Rolle der Hysterektomie bei Endometriose?", "a": "Kann erwogen werden, wenn initiale Behandlungen ineffektiv sind. Jedoch erleben etwa 25% rezidivierende Beckenschmerzen und 10% benötigen weitere Chirurgie.", "id": 55}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Welche vasomotorischen Symptome definiert die North American Menopause Society?", "a": "Hitzewallungen (rezidivierende, transiente Episoden von Flush, Schwitzen, Wärmegefühl am Oberkörper/Gesicht) und Nachtschweiß (Hitzewallungen mit Schwitzen während des Schlafs).", "id": 56}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Wie effektiv ist HRT bei vasomotorischen Symptomen?", "a": "HRT reduziert die Häufigkeit vasomotorischer Symptome um etwa 75% im Vergleich zu Placebo. HRT ist die wirksamste Therapie.", "id": 57}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was sind nicht-hormonelle Alternativen für vasomotorische Symptome?", "a": "SSRIs/SNRIs (Venlafaxin, Paroxetin), Fezolinetant, Clonidin, Gabapentin, Oxybutynin, Pregabalin. HRT ist jedoch überlegen.", "id": 58}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist die Behandlung des genitourinären Menopause-Syndroms?", "a": "Niedrig-dosiertes vaginales Östrogen, vaginales Dehydroepiandrosteron (DHEA) oder orales Ospemifen. Rezeptfreie vaginale Feuchtigkeitscremes sind nicht-inferior zu Östrogen.", "id": 59}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Sollte HRT zur Prävention chronischer Erkrankungen verwendet werden?", "a": "Nein. USPSTF empfiehlt gegen die Verwendung von HRT zur Prävention chronischer Erkrankungen bei postmenopausalen Frauen.", "id": 60}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist die Rolle von mikronisiertem Progesteron bei HRT?", "a": "Kann kontinuierlich statt zyklisch eingenommen werden, um monatliche Blutungen zu vermeiden. Bevorzugt wegen fehlender antiapoptotischer Eigenschaften auf Brustzellen.", "id": 61}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Welche Notfall-Medikation wird bei akuter schwerer Uterusblutung eingesetzt?", "a": "Intravenöses konjugiertes equines Östrogen für hämodynamisch instabile Patientinnen. Hochdosierte KOK oder orale Gestagene für stabile Patientinnen.", "id": 62}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist die Rolle von Tranexamsäure bei abnormer Uterusblutung?", "a": "Nicht-hormonale Option zur Reduktion von Blutungssymptomen. Kann oral oder intravenös (bei akuter Blutung) verabreicht werden.", "id": 63}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Wann sollte bei abnormer Uterusblutung an Koagulopathie gedacht werden?", "a": "Bei starker Menstruationsblutung seit Menarche, Anamnese von postpartaler Hämorrhagie, chirurgiebedingter Blutung, oder Familienanamnese von Blutungsstörungen.", "id": 64}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist die Prävalenz symptomatischer Uterusmyome?", "a": "Etwa 25% der Frauen mit Uterusmyomen haben Symptome, am häufigsten starke Menstruationsblutung (oft mit Anämie assoziiert).", "id": 65}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Welche Symptome verursachen Uterusmyome?", "a": "Starke Menstruationsblutung (häufigste), Beckendruck, Schmerzen, Bulk-Symptome (Druck, völlegefühl, Blasen-/Darmsymptome), selten Infertilität.", "id": 66}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist die Rolle von Ulipristalacetat bei Myomen?", "a": "Selektiver Progesteron-Rezeptor-Modulator, der Blutungs- und Bulk-Symptome reduziert. In einigen Ländern zugelassen, aber mit seltenen schweren Leberschäden assoziiert. Eingeschränkte Verwendung in Europa.", "id": 67}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Wann ist Expectant Management bei Myomen angemessen?", "a": "Bei asymptomatischen Patientinnen oder solchen, die keine Intervention wünschen. Besonders geeignet bei perimenopausalen Patientinnen.", "id": 68}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was passiert mit Myomen nach der Menopause?", "a": "Prävalenz klinisch signifikanter Myome sinkt nach der Menopause, da Myome nicht die notwendigen Östrogen- und Progesteronspiegel für Entwicklung und Wachstum haben.", "id": 69}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Welche Rolle spielen NSAIDs bei Myom-assoziierter Blutung?", "a": "NSAIDs können Blutungssymptome reduzieren, sind aber weniger effektiv als hormonelle Optionen. Oft als Zusatztherapie verwendet.", "id": 70}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist die Sensitivität des transvaginalen Ultraschalls für Myome und Adenomyose?", "a": "Sensitivität und Spezifität >90% für Myome und Adenomyose bei chronischen Beckenschmerzen.", "id": 71}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Welche Laboruntersuchungen sind bei abnormer Uterusblutung initial erforderlich?", "a": "Schwangerschaftstest (bei sexuell aktiven Frauen), komplettes Blutbild (CBC), TSH (zum Ausschluss von Schilddrüsendysfunktion), Prolaktin bei Verdacht.", "id": 72}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist die Rolle der Saline-Infusions-Sonohysterographie?", "a": "Kann notwendig sein, um anatomische Abnormalitäten auszuschließen, wenn transvaginaler Ultraschall nicht ausreichend ist. Alternative: Hysteroskopie.", "id": 73}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Welche Zykluslängen-Variabilität deutet auf Anovulation hin?", "a": "Zyklen, die in der Länge um mehr als 10 Tage von einem Zyklus zum anderen variieren, sind wahrscheinlich anovulatorisch.", "id": 74}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was sind typische Symptome ovulatorischer Blutungen?", "a": "Brustspannen, erhöhter mukoider vaginaler Ausfluss, prämenstruelle Krämpfe und Blähungen. Diese fehlen typischerweise bei anovulatorischen Blutungen.", "id": 75}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Welche HPV-Typen sind hochriskant für Zervixkarzinom?", "a": "HPV 16 und 18 sind die häufigsten hochrisiko-Typen. 97% der Präkanzerosen sind HPV-positiv.", "id": 76}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist der Vorteil von HPV-Selbstentnahme?", "a": "Erhöht Screening-Raten, besonders bei schwer erreichbaren Populationen. Weniger unangenehm, zugänglicher für Frauen in ländlichen Gebieten oder mit Transport-/Terminbarrieren.", "id": 77}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Sollten Frauen nach totaler Hysterektomie gescreent werden?", "a": "Nein, außer bei Anamnese von hochgradiger Präkanzerose (CIN 2/3) oder Zervixkarzinom.", "id": 78}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Wie wird ASCUS mit positivem HPV-Test gemanagt?", "a": "Kolposkopie ist indiziert bei ASCUS mit positivem HPV-Test.", "id": 79}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist das 4%-Risiko-Schwellenwert-Konzept der ASCCP 2019?", "a": "Sofortiges CIN3+-Risiko ≥4% ist der kritische Entscheidungspunkt für Kolposkopie. Risikobasiertes Management statt ergebnisbasiertes Protokoll.", "id": 80}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Welche Rolle spielt die HPV-Impfung beim Zervixkarzinom-Screening?", "a": "Screening-Empfehlungen gelten unabhängig vom HPV-Impfstatus. Geimpfte Personen sollten weiterhin nach Standardprotokollen gescreent werden.", "id": 81}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist die durchschnittliche Zeit von hochgradiger Präkanzerose zu invasivem Zervixkarzinom?", "a": "Etwa 10 Jahre, was ausreichend Zeit für Identifikation und Behandlung von Läsionen ermöglicht.", "id": 82}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Welche Patientinnen benötigen häufigeres Zervixkarzinom-Screening?", "a": "Immunsupprimierte Patientinnen (HIV, Organtransplantation, systemischer Lupus, entzündliche Darmerkrankungen, immunsuppressive Therapien) benötigen häufigeres Screening.", "id": 83}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist die Rolle von Reflex-HPV-Testing?", "a": "Bei abnormer Zytologie sollte HPV-Triage oder Reflex-HPV-Testing durchgeführt werden, um das weitere Management zu leiten.", "id": 84}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Welche Bildgebung ist bei Verdacht auf tief infiltrierende Endometriose indiziert?", "a": "MRT ist bevorzugt bei Verdacht auf tief infiltrierende Endometriose, die Darm, Blase oder andere Beckenstrukturen betrifft.", "id": 85}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was sind die drei häufigsten strukturellen gynäkologischen Erkrankungen?", "a": "Myome (starke Menstruationsblutung, Beckendruck), Endometriose (zyklische Beckenschmerzen, Dysmenorrhoe, Dyspareunie), Ovarialzysten (meist asymptomatisch).", "id": 86}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Welche GnRH-Therapie hat die kürzeste Halbwertszeit?", "a": "Elagolix hat eine kurze Halbwertszeit und erfordert zweimal tägliche Einnahme. Mit Östradiol und Norethindronacetat kombiniert für Myome zugelassen.", "id": 87}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist Relugolix?", "a": "Oraler GnRH-Antagonist mit längerer Halbwertszeit als Elagolix. Mit hormoneller Add-back-Therapie kombiniert zur Behandlung von Myom-Symptomen für bis zu 24 Monate zugelassen.", "id": 88}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Welche Nebenwirkungen haben GnRH-Agonisten/-Antagonisten?", "a": "Hypöstrogene Effekte: Kopfschmerzen, Hitzewallungen, Hypertonie, Verlust der Knochenmineraldichte. Add-back-Therapie mit niedrig-dosierten Östrogen/Gestagen mildert diese.", "id": 89}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist die Rolle der bariatrischen Chirurgie bei PCOS?", "a": "Kann basierend auf allgemeinen Populationsleitlinien erwogen werden, mit Abwägung von potenziellem Nutzen und Nebenwirkungen.", "id": 90}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Sollte Insulinresistenz bei PCOS routinemäßig gemessen werden?", "a": "Nein. Insulinresistenz ist ein Schlüsselmerkmal von PCOS, aber routinemäßig verfügbare Messungen sind ungenau und klinische Messung wird derzeit nicht empfohlen.", "id": 91}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Was ist die Rolle von Inositol bei PCOS?", "a": "Bietet limitierte klinische Vorteile bei PCOS. Metformin hat größere Wirksamkeit als Inositol.", "id": 92}, {"cat": "PCOS & Screening (Open Evidence)", "q": "Welche Ernährungsempfehlungen gibt es bei Endometriose?", "a": "Anti-inflammatorische Diät: Obst und Gemüse, Vollkornprodukte, mageres Protein, gesunde Fette, Gewürze.", "id": 93}, {"cat": "PCOS & Endokrinologie", "q": "Was ist die primäre Amenorrhoe?", "a": "Ausbleiben der Menarche bis 15. LJ mit sekundären Geschlechtsmerkmalen, oder bis 13. LJ ohne diese. Ursachen: Turner, MRKH, Hymenalatresie, Kallmann.", "id": 94}, {"cat": "PCOS & Endokrinologie", "q": "Was sind Ursachen der sekundären Amenorrhoe?", "a": "Schwangerschaft (ausschliessen!), Hyperprolaktinämie, PCOS, Hypothyreose, Hypothalamus-Amenorrhoe, Asherman, Klimakterium praecox.", "id": 95}, {"cat": "PCOS & Endokrinologie", "q": "Welches Blutungsmuster ist typisch bei Makroprolaktinämie?", "a": "Amenorrhoe (häufigste Manifestation durch GnRH-Hemmung). Auch: Galaktorrhoe, Libidoverlust, Infertilität.", "id": 96}, {"cat": "PCOS & Endokrinologie", "q": "Was ist Klimakterium praecox (POI)?", "a": "Prämature Ovarialinsuffizienz: Amenorrhoe >4 Monate + FSH >25 IU/L (2×, Abstand 4 Wochen) bei Frauen <40 Jahren. Therapie: HRT.", "id": 97}, {"cat": "PCOS & Endokrinologie", "q": "Wie wird die Ovulation sicher nachgewiesen?", "a": "Progesteron-Messung Zyklustag 21 (>10 ng/ml = Ovulation stattgefunden). Alternativ: biphasische Basaltemperaturkurve.", "id": 98}, {"cat": "PCOS & Endokrinologie", "q": "Was ist der Farnkrauttest?", "a": "Mikroskopischer Nachweis kristallinen Musters im Zervixschleim bei Östrogendominanz präovulatorisch. Fehlt in der Lutealphase.", "id": 99}, {"cat": "PCOS & Endokrinologie", "q": "Was ist das prämenstruelle Syndrom (PMS)?", "a": "Zyklische körperliche und psychische Symptome in Lutealphase, verschwinden mit Menstruation. Therapie: SSRI, KOK. Diagnose retrospektiv über 2 Zyklen.", "id": 100}, {"cat": "PCOS & Endokrinologie", "q": "Was ist Pubertas praecox?", "a": "Pubertätsbeginn vor dem 8. LJ bei Mädchen. Zentral: idiopathisch, ZNS-Tumor. Peripher (GnRH-unabhängig): Granulosazelltumor (Östrogen), NNR-Tumor (Androgen). Nicht: Hypothyreose.", "id": 101}, {"cat": "PCOS & Endokrinologie", "q": "Welche hormonellen Veränderungen sind typisch für die Postmenopause?", "a": "Erhöhte Gonadotropine (FSH, LH), erniedrigtes Östradiol und Progesteron. FSH >25–40 IU/L.", "id": 102}, {"cat": "PCOS & Endokrinologie", "q": "Welches Gestagen hat ausgeprägte antiandrogene Eigenschaften?", "a": "Cyproteronacetat (stärkste antiandrogene Wirkung). Auch Drospirenon leicht antiandrogen. Levonorgestrel, Gestoden: androgenartig.", "id": 103}, {"cat": "PCOS & Endokrinologie", "q": "Was bedeutet eine Abbruchblutung nach Gestagengabe?", "a": "Östrogenspiegel sind vorhanden (Endometrium ist aufgebaut). Gonadotropinproduktion vorhanden. Schliesst aus: Asherman, MRKH, Schwangerschaft.", "id": 104}, {"cat": "PCOS & Endokrinologie", "q": "Was ist das AGS (adrenogenitales Syndrom) und was ist die häufigste Ursache?", "a": "21-Hydroxylase-Mangel (90%): Kortisol-Synthesestörung → Androgen-Überschuss. Klinisch: Virilisierung, Pseudohermaphroditismus femininus, Salzverlustsyndrom.", "id": 105}, {"cat": "PCOS & Endokrinologie", "q": "Was ist die Rolle der Sella-turcica-MRI bei Hyperprolaktinämie?", "a": "Ausschluss eines Prolaktinoms (Adenom). Therapie Prolaktinom: Dopaminagonist (Cabergolin bevorzugt, Bromocriptin). Makroprolaktinom: Op wenn Kompression.", "id": 106}, {"cat": "Endometriose", "q": "Ist Laparoskopie für Endometriose-Diagnose zwingend?", "a": "Nein. Klinische Diagnose + Bildgebung (TVUS/MRT) ausreichend. Empirische Therapie ohne Op möglich.", "id": 107}, {"cat": "Endometriose", "q": "Was ist die Erstlinientherapie bei Endometriose ohne Kinderwunsch?", "a": "KOK oder Gestagene (Dienogest) ± NSAR. Kontinuierliche Einnahme besser als zyklisch.", "id": 108}, {"cat": "Endometriose", "q": "Wie lange dauert die diagnostische Verzögerung bei Endometriose?", "a": "5–12 Jahre. Die meisten Frauen konsultieren 3+ Ärzte vor der Diagnose.", "id": 109}, {"cat": "Endometriose", "q": "Was ist typisch für ein Endometriom (Schokoladenzyste) im Ultraschall?", "a": "Echoarmer Inhalt mit diffuser Echogenität ('Schokolade'). Oft bilateral. CA-125 erhöht.", "id": 110}, {"cat": "Endometriose", "q": "Was sind Risikofaktoren für Endometriose?", "a": "Frühe Menarche, kürzere Zyklen, niedriger BMI, Nulliparität, obstruktive Müller-Anomalien. Retrograde Menstruation als Pathomechanismus.", "id": 111}, {"cat": "Endometriose", "q": "Wann ist eine chirurgische Therapie bei Endometriose indiziert?", "a": "Wenn Hormontherapien ineffektiv/kontraindiziert, grosse Ovarialzysten (>4 cm), tief infiltrierende Endometriose mit schweren Symptomen, Kinderwunsch.", "id": 112}, {"cat": "Endometriose", "q": "Was ist eine schmerzhafte Verdickung des Septum rectovaginale?", "a": "Typisches Zeichen für tief infiltrierende Endometriose. MRT zur Ausdehnung. Laparoskopie für Diagnose und Therapie.", "id": 113}, {"cat": "Menopause & HRT", "q": "Was ist die Hauptindikation für HRT in der Menopause?", "a": "Behandlung moderater bis schwerer vasomotorischer Symptome (Hitzewallungen, Nachtschweiß). HRT reduziert diese um ~75%.", "id": 114}, {"cat": "Menopause & HRT", "q": "Welche Risiken hat kombinierte Östrogen-Gestagen-Therapie?", "a": "Erhöhtes VTE-Risiko, Schlaganfall, Brustkrebs bei Langzeitanwendung. Transdermale Gabe: geringeres VTE-Risiko.", "id": 115}, {"cat": "Menopause & HRT", "q": "Was sind nicht-hormonelle Alternativen für Hitzewallungen?", "a": "SSRIs/SNRIs (Venlafaxin), Fezolinetant (NK3-Antagonist), Clonidin, Gabapentin. HRT ist überlegen.", "id": 116}, {"cat": "Menopause & HRT", "q": "Warum ist transdermal bevorzugt bei HRT?", "a": "Kein First-pass-Effekt → geringere Wirkung auf Gerinnungsfaktoren → niedrigeres VTE-Risiko im Vergleich zu oraler Gabe.", "id": 117}, {"cat": "Menopause & HRT", "q": "Wie lange muss Gestagen bei HRT minimal gegeben werden?", "a": "Mind. 12–14 Tage/Monat bei zyklischer Anwendung oder kontinuierlich täglich. <10 Tage schützt Endometrium nicht.", "id": 118}, {"cat": "Menopause & HRT", "q": "Was ist die Rolle von mikronisiertem Progesteron?", "a": "Kann kontinuierlich gegeben werden (keine monatliche Blutung). Günstigeres Profil bzgl. Brust vs. synthetische Gestagene.", "id": 119}, {"cat": "Menopause & HRT", "q": "Welche Behandlung lindert Hitzewallungen in der Postmenopause NICHT?", "a": "Raloxifen (SERM) — kann Hitzewallungen sogar verstärken. Raloxifen: Osteoporoseprävention, kein VTE-Schutz.", "id": 120}, {"cat": "Abnorme Blutung & Myome", "q": "Wann Endometriumbiopsie bei abnormer Blutung?", "a": "Bei ≥45 Jahren, jüngere Frauen mit unopponierten Östrogenen (Adipositas, PCOS, Tamoxifen).", "id": 121}, {"cat": "Abnorme Blutung & Myome", "q": "Welche Behandlung führt am ehesten zur Myomverkleinerung?", "a": "GnRH-Analogon (3 Monate): 30–60% Volumenreduktion. Präoperativ sinnvoll.", "id": 122}, {"cat": "Abnorme Blutung & Myome", "q": "Was sind Notfallinterventionen bei hämodynamisch instabiler Uterusblutung?", "a": "Uterustamponade, i.v. Östrogen, Dilatation und Kürettage, Uterusarterienembolisation.", "id": 123}, {"cat": "Abnorme Blutung & Myome", "q": "Was ist die häufigste Komplikation eines Uterus myomatosus?", "a": "Eisenmangelanämie durch Hypermenorrhoe.", "id": 124}, {"cat": "Abnorme Blutung & Myome", "q": "Was ist UAE (Uterusarterienembolisation)?", "a": "Interventionell-radiologisches Verfahren bei Myomen. Gute Blutungsreduktion. Cave: eingeschränkte reproduktive Outcomes.", "id": 125}, {"cat": "Zervixkarzinom & Screening", "q": "Was ist die bevorzugte Screening-Methode für Zervixkarzinom?", "a": "Primäres HPV-Testing alle 5 Jahre (ab 30 Jahren) ist bevorzugt. Alternativ: Zytologie alle 3 Jahre.", "id": 126}, {"cat": "Zervixkarzinom & Screening", "q": "Was ist FIGO Stadium IIIB Zervixkarzinom?", "a": "Ausdehnung auf Beckenwand und/oder Hydronephrose. Therapie: Radiochemotherapie (Cisplatin).", "id": 127}, {"cat": "Zervixkarzinom & Screening", "q": "Was ist die Wertheim-Operation?", "a": "Radikale Hysterektomie + Parametriumresektion + Scheidenmanschette + pelvine Lymphadenektomie.", "id": 128}, {"cat": "Zervixkarzinom & Screening", "q": "Was trifft bei HSIL zu, die bei Kolposkopie nicht vollständig sichtbar ist?", "a": "Konisation ist indiziert (diagnostisch und therapeutisch). Endozervikale Läsion möglich.", "id": 129}, {"cat": "Zervixkarzinom & Screening", "q": "Welche HPV-Typen sind im 9-valenten Impfstoff?", "a": "HPV 6, 11, 16, 18, 31, 33, 45, 52, 58 — ~90% der Zervixkarzinome.", "id": 130}, {"cat": "Zervixkarzinom & Screening", "q": "Wie viele HPV-Impfdosen bei <15-Jährigen?", "a": "2 Dosen (0 und 6–12 Monate). Bei ≥15 Jahren: 3 Dosen (0, 1–2, 6 Monate).", "id": 131}, {"cat": "Zervixkarzinom & Screening", "q": "Was sind prädisponierende Faktoren für CIN?", "a": "HPV-Infektion (Hauptfaktor), häufige Partnerwechsel, Nikotinabusus, Immunsuppression. Anovulatorische Zyklen: kein Risikofaktor.", "id": 132}, {"cat": "Zervixkarzinom & Screening", "q": "Wann kann Zervixkarzinom-Screening beendet werden?", "a": "Mit 65 Jahren bei adäquatem vorherigem Screening und negativen Resultaten.", "id": 133}, {"cat": "Gynäkologische Onkologie", "q": "Welche BRCA-Mutationen erhöhen das Ovarialkarzinom-Risiko?", "a": "BRCA1: 40–60%. BRCA2: 15–25%. Prophylaktische Salpingo-Oophorektomie ab 35–40 Jahren (BRCA1) empfohlen.", "id": 134}, {"cat": "Gynäkologische Onkologie", "q": "Welcher Ovarialtumor ist ein Keimzelltumor?", "a": "Dysgerminom. Hohe Strahlensensibilität, gute Prognose. Granulosazelltumor ist Keimstrang-Stroma-Tumor.", "id": 135}, {"cat": "Gynäkologische Onkologie", "q": "Was ist die Therapie des nicht-metastasierenden Chorionkarzinoms?", "a": "Chemotherapie (Methotrexat, Heilungsrate >95%). Hysterektomie nur bei Therapieresistenz.", "id": 136}, {"cat": "Gynäkologische Onkologie", "q": "Was ist die korrekte Therapie bei Vulvakarzinom IA?", "a": "Weite lokale Exzision ohne Lymphonodektomie (LK-Risiko <1% bei IA = ≤2cm, ≤1mm Invasion).", "id": 137}, {"cat": "Gynäkologische Onkologie", "q": "Was ist typisch für ein Granulosazelltumor des Ovars?", "a": "Östrogen-produzierende Tumor → Endometriumhyperplasie, postmenopausale Blutung. Tumormarker: Inhibin, AMH.", "id": 138}, {"cat": "Gynäkologische Onkologie", "q": "Was ist interstitielle Zystitis/BPS?", "a": "Chronische Blasenschmerzen mit Drang ohne Infektion. Assoziiert mit Autoimmunerkrankungen. Therapie: PPS, DMSO, Amitriptylin.", "id": 139}, {"cat": "Gynäkologische Onkologie", "q": "Was sind Massnahmen zur Inzidenzsenkung des Ovarialkarzinoms?", "a": "Orale Antikonzeptiva, Tubensterilisation, prophylaktische Salpingo-Oophorektomie bei BRCA. CA-125/US reduzieren Inzidenz NICHT.", "id": 140}, {"cat": "Gynäkologische Onkologie", "q": "Was ist das Ausbreitungsmuster des Vulvakarzinoms?", "a": "Lokal tief infiltrierend, früh inguino-femorale LK-Metastasen, selten hämatogen.", "id": 141}, {"cat": "Geburtshilfe", "q": "Was sind die Kriterien der Präeklampsie?", "a": "Hypertonie ≥140/90 mmHg nach 20. SSW + mind. 1: Proteinurie ≥300mg/24h, Thrombozyten <100.000/μl, Kreatinin >97 μmol/l, AST/ALT >2×Norm, Lungenödem, neurologische Symptome.", "id": 142}, {"cat": "Geburtshilfe", "q": "Was sind HELLP-Kriterien?", "a": "Hämolyse + Elevated Liver enzymes + Low Platelets (<100.000/μl). Oft ohne schwere Hypertonie.", "id": 143}, {"cat": "Geburtshilfe", "q": "Was ist der Bishop-Score und wann ist Einleitung günstig?", "a": "Bewertet Zervixreife (Öffnung, Verkürzung, Konsistenz, Position, Höhenstand). ≥6 Punkte: günstig für Oxytocin. <6: Prostaglandine/Ballon zuerst.", "id": 144}, {"cat": "Geburtshilfe", "q": "Was ist Tokolyse und welches Mittel ist in CH erste Wahl?", "a": "Wehenhemmung bei drohender Frühgeburt. Atosiban (Oxytozin-Antagonist, 1. Wahl in CH), Nifedipin, Betamimetika. Ziel: Zeitgewinn für Steroidgabe.", "id": 145}, {"cat": "Geburtshilfe", "q": "Was bewirkt antenatale Steroidgabe (Betamethason)?", "a": "Senkt neonatale Mortalität, reduziert Atemnotsyndrom, intrakranielle Blutungen, NEC. Indikation: 24.–34. SSW.", "id": 146}, {"cat": "Geburtshilfe", "q": "Was ist das Vorgehen bei PPROM (Blasensprung vor 37. SSW)?", "a": "Hospitalisierung, Abstriche, CRP, Leukozyten, CTG. Steroidgabe (24–34. SSW), Antibiotika (Erythromycin 10 Tage), GBS-Prophylaxe. Entbindung bei Chorioamnionitis.", "id": 147}, {"cat": "Geburtshilfe", "q": "Was sind die 4 T's der postpartalen Hämorrhagie?", "a": "Tonus (~80%, atonischer Uterus), Trauma, Tissue (Plazentatretention), Thrombin. PPH: >500ml vaginal, >1000ml nach Sectio.", "id": 148}, {"cat": "Geburtshilfe", "q": "Wie wird postpartale Hämorrhagie behandelt?", "a": "Uterotonika (Oxytocin, Carbetocin, Methylergometrin, Misoprostol), bimanuelle Kompression, Ballontamponade, B-Lynch-Naht, Embolisierung, Hysterektomie.", "id": 149}, {"cat": "Geburtshilfe", "q": "Was ist Placenta accreta spectrum?", "a": "Abnorme Trophoblastinvasion. Risikofaktoren: Sectionarbe + Placenta praevia. Blutverlust >2–3 Liter, oft Hysterektomie nötig.", "id": 150}, {"cat": "Geburtshilfe", "q": "Was sind Ursachen des Polyhydramnions?", "a": "Fetale Schluckstörungen (Ösophagusatresie), Herzfehler, schlecht eingestellter GDM. Nicht: Plazentainsuffizienz (→ Oligohydramnion).", "id": 151}, {"cat": "Geburtshilfe", "q": "Was sind Ursachen des Oligohydramnions?", "a": "Fetale Nierenagenese/-dysplasie, IUGR (Plazentainsuffizienz), PPROM, Blasenauslassobstruktion.", "id": 152}, {"cat": "Geburtshilfe", "q": "Was sind Komplikationen des chronischen Oligohydramnions?", "a": "Lungenhypoplasie, Gesichtsverformungen, Klumpfüsse, Gelenkkontrakturen. Nicht: Niereninsuffizienz (Ursache, nicht Folge).", "id": 153}, {"cat": "Geburtshilfe", "q": "Was ist der Erste-Trimester-Test?", "a": "Kombiniertes Screening 11+0–13+6 SSW: Nackentransparenz, PAPP-A, freies β-HCG. Detektionsrate Trisomie 21: ~90%.", "id": 154}, {"cat": "Geburtshilfe", "q": "Was ist der sensitivste Parameter für Aneuploidie-Screening in der 12. SSW?", "a": "Fetale Nackentransparenz (NT). In Kombination mit PAPP-A und β-HCG: Detektionsrate ~90%.", "id": 155}, {"cat": "Geburtshilfe", "q": "Welche Zeichen weisen im Ultraschall auf Spina bifida hin?", "a": "Banana-Sign (Kleinhirn durch Arnold-Chiari-Malformation), Lemon-Sign (Schädelverformung). AFP im 2. Trimenon erhöht.", "id": 156}, {"cat": "Geburtshilfe", "q": "Wann ist Magnesium i.v. bei Präeklampsie indiziert?", "a": "Bei schwerer Präeklampsie zur Eklampsie-Prophylaxe und bei Eklampsie. Antidot: Kalziumglukonat.", "id": 157}, {"cat": "Geburtshilfe", "q": "Was ist Cholestase gravidique?", "a": "Pruritus + erhöhte Gallensäuren + erhöhtes Totgeburtsrisiko. Therapie: Ursodeoxycholsäure. Entbindung: 37.–38. SSW.", "id": 158}, {"cat": "Geburtshilfe", "q": "Was ist anti-D-Prophylaxe?", "a": "Verhindert Rhesussensibilisierung Rh-negativer Mütter. 28. SSW + nach Geburt eines Rh+-Kindes innerhalb 72h.", "id": 159}, {"cat": "Geburtshilfe", "q": "Was ist das Vorgehen bei Nabelschnurvorfall?", "a": "NOTFALL-Sectio! Bis dahin: Knie-Ellenbogen-Lage, vorangehenden Teil hochhalten, i.v. Tokolyse. Syntocinon kontraindiziert.", "id": 160}, {"cat": "Geburtshilfe", "q": "Welche physiologischen Veränderungen sind in der Schwangerschaft NICHT zu beobachten?", "a": "Anstieg des arteriellen Blutdrucks und Gefässwiderstands (sinken!). Herzfrequenz steigt, Blutvolumen steigt, RR sinkt.", "id": 161}, {"cat": "Geburtshilfe", "q": "Was ist Schulterdystokie und wie wird sie behandelt?", "a": "Schulter klemmt hinter Symphyse. McRoberts-Manöver (max. Oberschenkelflexion) + suprapubischer Druck schräg. NICHT: axialer Zug am Kopf, Druck auf Fundus.", "id": 162}, {"cat": "Geburtshilfe", "q": "Welche Antibiotika sind in der Schwangerschaft absolut kontraindiziert?", "a": "Tetrazykline (Knochen/Zähne), Chinolone (Knorpel). Sulfonamide im 3. Trimenon (Kernikterus). Chloramphenicol (Grey-Baby).", "id": 163}, {"cat": "Geburtshilfe", "q": "Was ist Mekoniumaspirationssyndrom?", "a": "Aspiration mekoniumhaltigen Fruchtwassers bei reifen Feten. Röntgen: fleckige Verschattungen. Cave: PPHN, Pneumothorax.", "id": 164}, {"cat": "Geburtshilfe", "q": "Was ist IUGR und wie wird es diagnostiziert?", "a": "Wachstumsretardierung: Schätzgewicht <3. Perz. oder <10. Perz. + Doppler-Anomalie. Frühes IUGR (<32 SSW) vs. spätes (≥32 SSW).", "id": 165}, {"cat": "Geburtshilfe", "q": "Was ist Insertio velamentosa der Nabelschnur?", "a": "Nabelschnur inseriert auf Eihäuten. Bei Blasensprung: Vasa praevia → massive fetale Blutung. Lebensbedrohlich für Fetus.", "id": 166}, {"cat": "Geburtshilfe", "q": "Was ist Hyperemesis gravidarum?", "a": "Schwere Übelkeit/Erbrechen + Gewichtsverlust >5%, Dehydratation. Gehäuft bei Mehrlingen, Blasenmole. Therapie: Rehydratation, Antiemetika.", "id": 167}, {"cat": "Geburtshilfe", "q": "Was ist Chorioamnionitis und wie wird sie behandelt?", "a": "Infektion der Eihäute: Fieber, maternale/fetale Tachykardie, Uterusdruckschmerz. Therapie: sofortige Entbindung + i.v. Breitband-Antibiotika.", "id": 168}, {"cat": "Geburtshilfe", "q": "Was ist das Vorgehen bei intrauterinem Fruchttod im 3. Trimenon?", "a": "Geburtseinleitung (vaginaler Weg bevorzugt): Mifepriston + Misoprostol oder Oxytocin. Thromboseprophylaxe. Psychologische Betreuung.", "id": 169}, {"cat": "Geburtshilfe", "q": "Was ist Hyperemesis gravidarum und wann tritt sie gehäuft auf?", "a": "Schwere persistierende Übelkeit/Erbrechen mit Dehydratation. Häufiger bei: Mehrlingen, Blasenmole, psychosozialen Problemen.", "id": 170}, {"cat": "Urogynäkologie & Inkontinenz", "q": "Was ist die Erstlinientherapie bei Stressinkontinenz?", "a": "Beckenbodentraining (Physiotherapie), Gewichtsreduktion. Chirurgisch: TVT (Tension-free Vaginal Tape) oder Kolposuspension nach Burch.", "id": 171}, {"cat": "Urogynäkologie & Inkontinenz", "q": "Welche Erfolgsrate hat TVT?", "a": "77,7–80,8% objektive Heilungsrate nach 1 Jahr. Mesh-Erosion ~5% Langzeitkomplikation.", "id": 172}, {"cat": "Urogynäkologie & Inkontinenz", "q": "Was ist der Unterschied zwischen retropubischem und transobturatorischem TVT?", "a": "Retropubisch: höhere Heilungsrate. Transobturatorisch: geringeres Risiko für Blasenperforation und Miktionsstörungen.", "id": 173}, {"cat": "Urogynäkologie & Inkontinenz", "q": "Was sind die Amsel-Kriterien?", "a": "3 von 4: grau-weisser Ausfluss, >20% Clue cells, pH >4,5, positiver Amintest. Diagnose der bakteriellen Vaginose.", "id": 174}, {"cat": "Urogynäkologie & Inkontinenz", "q": "Was ist die Erstlinientherapie bei Dranginkontinenz?", "a": "Verhaltenstherapie + Blasentraining. Medikamentös: Anticholinergika (Oxybutynin) oder Mirabegron (Beta-3-Agonist).", "id": 175}, {"cat": "Urogynäkologie & Inkontinenz", "q": "Wann ist Botox bei überaktiver Blase indiziert?", "a": "Bei Versagen oder Intoleranz von Anticholinergika. Dosis: 100 Einheiten intradetrusor.", "id": 176}, {"cat": "Urogynäkologie & Inkontinenz", "q": "Was ist die POP-Q-Klassifikation?", "a": "Standardisierte Descensus-Messung, Stadien 0–IV. Stadium II = ±1 cm vom Hymen. Stadium IV = kompletter Prolaps.", "id": 177}, {"cat": "Urogynäkologie & Inkontinenz", "q": "Was ist die Erstlinientherapie bei Genitalprolaps?", "a": "Pessartherapie und Beckenbodenphysiotherapie. Chirurgie wenn konservativ insuffizient.", "id": 178}, {"cat": "Urogynäkologie & Inkontinenz", "q": "Was beurteilt die Zystotonometrie?", "a": "Detrusoraktivität, Urethralsphinkterfunktion, Lage der proximalen Urethra, neurologische Funktionsstörungen.", "id": 179}, {"cat": "Urogynäkologie & Inkontinenz", "q": "Was ist Clue cells?", "a": "Vaginale Epithelzellen dicht besetzt mit Bakterien (Gardnerella). Charakteristisch für bakterielle Vaginose. Sichtbar im Nativpräparat.", "id": 180}, {"cat": "Urogynäkologie & Inkontinenz", "q": "Was ist die Therapie der bakteriellen Vaginose?", "a": "Metronidazol 500mg 2× täglich für 7 Tage ODER Metronidazol 0,75% Gel intravaginal.", "id": 181}, {"cat": "Urogynäkologie & Inkontinenz", "q": "Was ist interstitielle Zystitis?", "a": "Chronische Blasenschmerzen mit Harndrang ohne Infektion. Ausschlussdiagnose. Assoziiert mit Autoimmunerkrankungen. Koffein verschlechtert.", "id": 182}, {"cat": "Urogynäkologie & Inkontinenz", "q": "Was ist die chirurgische Therapie bei Uterusprolaps?", "a": "Vaginale Hysterektomie mit Apexsuspension. Sacrocolpopexie: höchste Erfolgsrate >90%.", "id": 183}, {"cat": "Infektiologie & STI", "q": "Was ist die Erstlinientherapie bei Chlamydien?", "a": "Doxycyclin 100mg 2× täglich für 7 Tage. Alternative: Azithromycin 1g Einzeldosis.", "id": 184}, {"cat": "Infektiologie & STI", "q": "Was ist Fitz-Hugh-Curtis-Syndrom?", "a": "Perihepatitis als PID-Komplikation (Chlamydien/Gonorrhoe). Klinisch: rechtsseitiger Oberbauchschmerz.", "id": 185}, {"cat": "Infektiologie & STI", "q": "Was ist die aktuelle Therapie bei unkomplizierter Gonorrhoe?", "a": "Ceftriaxon 500mg i.m. Einzeldosis. Azithromycin: nicht mehr empfohlen wegen Resistenz.", "id": 186}, {"cat": "Infektiologie & STI", "q": "Was ist das Ulcus durum?", "a": "Primäre Syphilis: schmerzloses induriertes Ulkus (Treponema pallidum). Inkubation: 7–90 Tage.", "id": 187}, {"cat": "Infektiologie & STI", "q": "Welche Stadien der Syphilis gibt es?", "a": "Primär (Ulcus durum), Sekundär (Exanthem Handflächen/Fusssohlen, Condylomata lata), Latent, Tertiär (Neurosyphilis, Gummen).", "id": 188}, {"cat": "Infektiologie & STI", "q": "Was ist die Therapie der Primär-/Sekundärsyphilis?", "a": "Benzathin-Penicillin G 2,4 Mio. Einheiten i.m. Einzeldosis.", "id": 189}, {"cat": "Infektiologie & STI", "q": "Was ist der Unterschied zwischen Herpes-Primärinfektion und Rezidiv?", "a": "Primär: schwerer, 2–3 Wochen, systemische Symptome. Rezidiv: milder, 7–10 Tage, lokalisiert.", "id": 190}, {"cat": "Infektiologie & STI", "q": "Was ist die Therapie bei Herpes-Erstmanifestation?", "a": "Valacyclovir 1g 2× täglich für 7–10 Tage. Suppressionstherapie: 500mg täglich.", "id": 191}, {"cat": "Infektiologie & STI", "q": "Wie wird Trichomonas vaginalis diagnostiziert und behandelt?", "a": "NAAT (Sensitivität 95–100%). Therapie: Metronidazol 500mg 2× täglich für 7 Tage (Frauen).", "id": 192}, {"cat": "Infektiologie & STI", "q": "Was sind Condylomata acuminata?", "a": "Genitalwarzen durch HPV 6 und 11. Therapie: Podophyllotoxin, Imiquimod oder Kryotherapie.", "id": 193}, {"cat": "Infektiologie & STI", "q": "Was ist die Therapie des Bartholin-Abszesses?", "a": "Marsupialisation (Rezidiv ~8,3%) oder Word-Katheter für 4–6 Wochen. Einfache I+D: hohe Rezidivrate ~34,5%.", "id": 194}, {"cat": "Infektiologie & STI", "q": "Was verursacht Chlamydia trachomatis?", "a": "Urethritis, Zervizitis, Adnexitis, Tubo-Ovarialabszess, Fitz-Hugh-Curtis-Syndrom, Reiter-Syndrom. NICHT: Pruritus vulvae.", "id": 195}, {"cat": "Infektiologie & STI", "q": "Welche Abstrichorte sind bei Gonorrhoe nicht geeignet?", "a": "Vagina (kein direkter Abstrich). Geeignet: Zervikalkanal, Urethra, Anus, Rachen.", "id": 196}, {"cat": "Reproduktionsmedizin & Recht CH", "q": "Was sind Indikationen für IVF?", "a": "Tubenverschluss, schwere Endometriose, schwere männliche Infertilität, unerklärte Infertilität, Frauen ≥38 Jahre.", "id": 197}, {"cat": "Reproduktionsmedizin & Recht CH", "q": "Was ist die Indikation für ICSI?", "a": "Schwere OAT, Azoospermie mit chirurgischer Spermiengewinnung (TESE/MESA), Status post Vasektomie.", "id": 198}, {"cat": "Reproduktionsmedizin & Recht CH", "q": "Ist Leihmutterschaft in der Schweiz erlaubt?", "a": "Nein, verboten nach Schweizer Fortpflanzungsmedizingesetz (FMedG).", "id": 199}, {"cat": "Reproduktionsmedizin & Recht CH", "q": "Ist Samenspende in der Schweiz erlaubt?", "a": "Ja. Kind hat Recht auf Kenntnis der Abstammung ab 18 Jahren. Nur für heterosexuelle Paare (ehe- oder eingetragene Partnerschaft).", "id": 200}, {"cat": "Reproduktionsmedizin & Recht CH", "q": "Ist Eizellspende in der Schweiz erlaubt?", "a": "Ja, seit 2017. Nur für heterosexuelle Paare.", "id": 201}, {"cat": "Reproduktionsmedizin & Recht CH", "q": "Ist PID (Präimplantationsdiagnostik) in der Schweiz erlaubt?", "a": "Ja, seit 2017 bei hohem Risiko für schwere Erbkrankheit oder Chromosomenstörung.", "id": 202}, {"cat": "Reproduktionsmedizin & Recht CH", "q": "Was ist OHSS?", "a": "Ovarielles Hyperstimulationssyndrom: Aszites, Pleuraergüsse, Thromboserisiko. Prävention: GnRH-Antagonisten, Freeze-all.", "id": 203}, {"cat": "Reproduktionsmedizin & Recht CH", "q": "Welche Erfolgsrate hat IVF bei Frauen <35 Jahren?", "a": "~40–50% Lebendgeburtenrate pro Zyklus. >40 Jahre: ~10–20%.", "id": 204}, {"cat": "Reproduktionsmedizin & Recht CH", "q": "Was ist die sekundäre Sterilität am häufigsten bedingt durch (25–30 J.)?", "a": "Tubenverschluss nach Salpingitis. Erste diagnostische Massnahme: Hysterosalpingographie.", "id": 205}, {"cat": "Reproduktionsmedizin & Recht CH", "q": "Was ist Hyperprolaktinämie und wie wird sie behandelt?", "a": "Erhöhtes Prolaktin → Amenorrhoe, Galaktorrhoe, Infertilität. Therapie: Dopaminagonist (Cabergolin).", "id": 206}, {"cat": "Kontrazeption", "q": "Welche Gestagene haben antiandrogene Eigenschaften?", "a": "Cyproteronacetat (stärkste), Drospirenon, Chlormadinon. Levonorgestrel, Gestoden: androgenartig.", "id": 207}, {"cat": "Kontrazeption", "q": "Was ist die häufigste Nebenwirkung der Levonorgestrel-IUD (Mirena)?", "a": "Metrorrhagie in den ersten 3–6 Monaten. Langfristig: Amenorrhoe bei ~20%.", "id": 208}, {"cat": "Kontrazeption", "q": "Welche Medikamente vermindern die kontrazeptive Sicherheit der Pille?", "a": "Antiepileptika (Carbamazepin, Phenytoin), Rifampicin, Johanniskraut. Nicht: Antitussiva, Antiemetika.", "id": 209}, {"cat": "Kontrazeption", "q": "Wie wirkt SHBG unter Einnahme der Pille?", "a": "SHBG steigt an (Östrogen stimuliert Leberproduktion). Weniger freies Testosteron → Verbesserung von Akne und Hirsutismus.", "id": 210}, {"cat": "Kontrazeption", "q": "Wann ist Notfallkontrazeption indiziert?", "a": "Innerhalb 72h (max. 120h) nach ungeschütztem GV. Levonorgestrel 1,5mg bis 72h. Ulipristalacetat bis 120h. Kupfer-IUD am effektivsten bis 120h.", "id": 211}, {"cat": "Kontrazeption", "q": "Was ist bei der Pille beim Stillen zu beachten?", "a": "KOK (östrogenhaltig) reduziert Milchmenge — kontraindiziert beim Stillen. Gestagenmonopräparate (Mini-Pille) sind erlaubt.", "id": 212}, {"cat": "Kontrazeption", "q": "Was ist die Fristenlösung in der Schweiz?", "a": "Straflos bis 12. SSW auf Wunsch der Frau (Art. 119 StGB). Beratungsgespräch + schriftliches Gesuch erforderlich.", "id": 213}, {"cat": "Kontrazeption", "q": "Was entspricht eine Hypoandrogenämie sexuell?", "a": "Libidomangel (verminderte sexuelle Lust/sexuelles Verlangen).", "id": 214}, {"cat": "Kontrazeption", "q": "Welche Kontrazeption bei 19-jähriger mit Dysmenorrhoe und Hypermenorrhoe?", "a": "KOK (erste Wahl: reduziert Blutung und Dysmenorrhoe). Alternativ: Mirena (LNG-IUS).", "id": 215}, {"cat": "Kontrazeption", "q": "Was ist die postkoitale Kontrazeption (YuzpeMethode)?", "a": "Hochdosierte Östrogen-Gestagen-Kombination effektiv, aber nicht durch Verhinderung der Fertilisierung. Wirkt durch Endometrium-Veränderung. Ersetzt durch LNG oder UPA.", "id": 216}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was ist das MRKH-Syndrom?", "a": "Aplasie von Uterus und oberen 2/3 der Vagina bei normalem 46,XX-Karyotyp und normalen Ovarien. Primäre Amenorrhoe, normale Geschlechtsmerkmale.", "id": 217}, {"cat": "Fehlbildungen & Neonatologie", "q": "Wie stellen sich Ovarien beim Turner-Syndrom dar?", "a": "Bindegewebige Stränge ('streak gonads'). Keine Pubertät. Typisch: Aortenisthmusstenose (35%), Hufeiseniere, Pterygium colli.", "id": 218}, {"cat": "Fehlbildungen & Neonatologie", "q": "Aus welcher Anlage entwickelt sich der Gartnersche Gang?", "a": "Wolff'scher (mesonephrischer) Gang. Reste als Gartnersche-Gang-Zysten an Scheidenvorderwand.", "id": 219}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was ist das Apgar-Schema?", "a": "Bewertung 1., 5., 10. Minute: Atmung, Puls, Grundtonus, Aussehen, Reflexe (je 0–2). 7–10: normal; 4–6: mässig deprimiert; 0–3: schwer.", "id": 220}, {"cat": "Fehlbildungen & Neonatologie", "q": "Welcher pH definiert neonatale Asphyxie?", "a": "pH <7,0 oder Base Excess ≤-12 mmol/L im Nabelschnurblut.", "id": 221}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was ist eine kongenitale Zwerchfellhernie?", "a": "Defekt meist links: Abdominalmorgane in Thorax → Lungenhypoplasie, pulmonale Hypertension. Röntgen: Darmschlingen im Thorax.", "id": 222}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was ist die häufigste Komplikation nach Terminsectio?", "a": "Atemnotsyndrom (nasse Lunge). Fehlende Katecholaminausschüttung → weniger Lungenflüssigkeits-Clearance.", "id": 223}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was sind Zeichen einer Trisomie 18 im Ultraschall?", "a": "Muskuläre VSD, kurze Femura, Double-bubble (Duodenalatresie), Choroid-Plexus-Zysten, Klumpfuss, überlappende Finger.", "id": 224}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was sind Folgen einer Hymenalatresie?", "a": "Primäre Amenorrhoe, kolikartige Unterbauchschmerzen, Hämatokolpos → Hämatometra. Therapie: Hymenalinzision.", "id": 225}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was sind Ziele der Wochenbettgymnastik?", "a": "Thromboseprophylaxe, Blasen-/Darmfunktion fördern, Beckenbodenmuskulatur kräftigen, Deszensus vorbeugen. NICHT: Uterusinvolution beschleunigen.", "id": 226}, {"cat": "Fehlbildungen & Neonatologie", "q": "Bei einem NG mit Zyanose ohne Besserung unter O2 — Differenzialdiagnose?", "a": "Kongenitaler Herzfehler (zyanotisch: Transposition, Fallot, TAPVR), persistierende pulmonale Hypertension.", "id": 227}, {"cat": "Statistik & Studiendesign", "q": "Was sind Sensitivität und Spezifität?", "a": "Sensitivität = RP/(RP+FN): Anteil richtig erkannter Kranker. Spezifität = RN/(RN+FP): Anteil richtig erkannter Gesunder.", "id": 228}, {"cat": "Statistik & Studiendesign", "q": "Was ist der positive prädiktive Wert (PPW)?", "a": "PPW = RP/(RP+FP). Anteil wirklich Kranker unter positiv Getesteten. Stark abhängig von Prävalenz.", "id": 229}, {"cat": "Statistik & Studiendesign", "q": "Was ist NNT?", "a": "Number Needed to Treat = 1/ARR (absolute Risikoreduktion). Niedrige NNT = effektive Therapie.", "id": 230}, {"cat": "Statistik & Studiendesign", "q": "Was ist der Unterschied zwischen Inzidenz und Prävalenz?", "a": "Inzidenz: Neuerkrankungen pro Zeit. Prävalenz: alle Erkrankten zu einem Zeitpunkt. Prävalenz = Inzidenz × Krankheitsdauer.", "id": 231}, {"cat": "Statistik & Studiendesign", "q": "Welcher Studientyp hat den höchsten Evidenzgrad?", "a": "Systematischer Review/Meta-Analyse von RCTs. Dann: RCT, Kohortenstudie, Fall-Kontroll, Querschnittsstudie.", "id": 232}, {"cat": "Statistik & Studiendesign", "q": "Was ist relatives vs. absolutes Risiko?", "a": "Relatives Risiko: Verhältnis der Risiken. Absolutes Risiko: Differenz der Risiken. NNT = 1/ARR.", "id": 233}, {"cat": "Geburtshilfe – CTG & Geburtsleitung", "q": "Was sind die drei CTG-Kategorien nach ACOG/NICHD?", "a": "Kat. I = normal (Baseline 110–160, moderate Variabilität, keine späten/variablen Dezelerationen). Kat. II = indeterminiert. Kat. III = abnormal (fehlende Variabilität + rezidivierende späte/variable Dezelerationen oder Bradykardie oder Sinusmuster).", "id": 234}, {"cat": "Geburtshilfe – CTG & Geburtsleitung", "q": "Was bedeutet 'moderate Variabilität' im CTG?", "a": "Schwankungen der FHR-Baseline von 6–25 bpm. Zuverlässigster Marker für fetales Wohlbefinden, schliesst schädigende Hypoxie weitgehend aus.", "id": 235}, {"cat": "Geburtshilfe – CTG & Geburtsleitung", "q": "Welches Management ist bei Kategorie-I-CTG empfohlen?", "a": "Routine-Intrapartum-Überwachung, keine spezifische Intervention erforderlich.", "id": 236}, {"cat": "Geburtshilfe – CTG & Geburtsleitung", "q": "Welche intrauterinen Reanimationsmassnahmen bei Kategorie-II-CTG?", "a": "Lageänderung der Mutter, Amnioinfusion, i.v.-Flüssigkeitsbolus, Reduktion/Stopp Oxytocin, Korrektur mütterlicher Pathologie (z.B. Hypotension).", "id": 237}, {"cat": "Geburtshilfe – CTG & Geburtsleitung", "q": "Wann ist beschleunigte Entbindung bei Kategorie-III-CTG indiziert?", "a": "Wenn CTG nach initialen Reanimationsmassnahmen persistiert → sofortige Entbindung (vaginal-operativ oder Sectio).", "id": 238}, {"cat": "Geburtshilfe – CTG & Geburtsleitung", "q": "Ist routinemässige O₂-Gabe bei Kat. II/III-CTG empfohlen?", "a": "Nein – ACOG empfiehlt gegen routinemässige O₂-Gabe ohne mütterliche Hypoxie. Meta-Analyse von 16 RCTs zeigte keinen Nutzen.", "id": 239}, {"cat": "Geburtshilfe – CTG & Geburtsleitung", "q": "Was ist Tachysystolie und wie wird sie behandelt?", "a": ">5 Kontraktionen in 10 min über 30 min. Bei assoziierten FHR-Veränderungen: Oxytocin pausieren, bei Persistenz schnell wirkendes Tokolytikum (z.B. Terbutalin).", "id": 240}, {"cat": "Geburtshilfe – CTG & Geburtsleitung", "q": "Was sind 'High-Risk Features' eines Kategorie-II-CTG?", "a": "Fehlende Variabilität ohne Akzelerationen, rezidivierende variable Dezelerationen mit langsamer Erholung, prolongierte Dezelerationen, steigende Baseline.", "id": 241}, {"cat": "Geburtshilfe – CTG & Geburtsleitung", "q": "Was sind Akzelerationen im CTG und welche Bedeutung haben sie?", "a": "FHR-Anstieg ≥15 bpm über ≥15 s (ab 32 SSW). Marker für fetales Wohlbefinden. Helfen bei Einschätzung des fetalen Status bei Kat.-II-CTG.", "id": 242}, {"cat": "Geburtshilfe – CTG & Geburtsleitung", "q": "Was ist ein sinusoidales CTG-Muster?", "a": "Gleichmässige Schwingungen der Baseline (2–5 Zyklen/min, 5–15 bpm) über >30 min ohne Variabilität. Assoziiert mit fetaler Anämie (Rh-Inkompatibilität). Kategorie III → operative Entbindung.", "id": 243}, {"cat": "Geburtshilfe – Operative Geburt", "q": "Was sind Voraussetzungen für operative vaginale Entbindung?", "a": "Vollständige Muttermundseröffnung, gesprungene Fruchtblase, eingestellter Kopf, bekannte Kopfposition, adäquate Analgesie, leere Blase, informierte Einwilligung.", "id": 244}, {"cat": "Geburtshilfe – Operative Geburt", "q": "Welche Kontraindikationen bestehen für vaginal-operative Entbindung?", "a": "Nicht eingestellter Kopf, unbekannte Kopfposition, fetale Knochenerkrankung (Osteogenesis imperfecta), Blutungsneigung (Alloimmunthrombozytopenie, Hämophilie).", "id": 245}, {"cat": "Geburtshilfe – Operative Geburt", "q": "Forceps vs. Vakuum: Was hat höhere Erfolgsrate?", "a": "Forceps hat höhere Erfolgsrate (Vakuum: RR 0,65 für Versagen vs. Forceps). Forceps: mehr Dammrisse III°/IV° (RR 1,89). Vakuum: häufiger Kephalhämatom, Subgalealhämatom.", "id": 246}, {"cat": "Geburtshilfe – Operative Geburt", "q": "Welche neonatalen Komplikationen hat Vakuumextraktion?", "a": "Kopfhautlazeration, Kephalhämatom (häufiger als Forceps), Subgalealhämatom, intrakranielle Blutung, Netzhautblutung, Hyperbilirubinämie.", "id": 247}, {"cat": "Geburtshilfe – Operative Geburt", "q": "Ab welchem Gestationsalter ist Vakuumextraktion kontraindiziert?", "a": "Vor 34 SSW nicht empfohlen (keine sichere Untergrenze etabliert, ACOG Level C).", "id": 248}, {"cat": "Geburtshilfe – Operative Geburt", "q": "Ist sequenzielle Anwendung von Vakuum und Forceps empfohlen?", "a": "Nein – assoziiert mit erhöhten neonatalen Komplikationsraten, nicht routinemässig durchführen.", "id": 249}, {"cat": "Geburtshilfe – Operative Geburt", "q": "Was ist der Unterschied zwischen Outlet-, Low- und Mid-Forceps?", "a": "Outlet: Kopf sichtbar auf Beckenboden, Rotation ≤45°. Low: Leitstelle ≥+2, Rotation ≤45°. Mid: Kopf eingestellt, Leitstelle über +2.", "id": 250}, {"cat": "Geburtshilfe – Operative Geburt", "q": "Ist eine routinemässige Episiotomie bei operativer Entbindung empfohlen?", "a": "Nein – ACOG empfiehlt dagegen wegen schlechter Heilung (mediolateral) und erhöhtem Sphinkter-Verletzungsrisiko (median).", "id": 251}, {"cat": "Geburtshilfe – Operative Geburt", "q": "Wie häufig ist Beckenendlage am Termin?", "a": "Ca. 3–4% aller Termingeburten.", "id": 252}, {"cat": "Geburtshilfe – Operative Geburt", "q": "Was ist die empfohlene Erstmassnahme bei Beckenendlage am Termin?", "a": "Äussere Wendung (ECV) ab 37 SSW, wenn keine Kontraindikation besteht. Erfolgsrate 37–60%. Spinalanästhesie erhöht Erfolgsrate signifikant.", "id": 253}, {"cat": "Geburtshilfe – Operative Geburt", "q": "Um wie viel reduziert eine erfolgreiche ECV die Sectiorate?", "a": "Meta-Analyse: Reduktion um 43% ohne signifikante Unterschiede bei Komplikationen.", "id": 254}, {"cat": "Geburtshilfe – Operative Geburt", "q": "Wie wird eine Querlage (transverse lie) unter der Geburt behandelt?", "a": "ECV unter Tokolyse bei intakter Fruchtblase (Erfolgsrate ~83%). Bei Versagen: Sectio.", "id": 255}, {"cat": "Geburtshilfe – Operative Geburt", "q": "Was ist das Vorgehen bei Schulterdystokie?", "a": "McRoberts-Manöver (maximale Oberschenkelflexion der Mutter gegen das Becken) + suprapubischer Druck schräg (Einleitung der Schulter). NICHT: axialer Zug am Kopf, Druck auf Fundus.", "id": 256}, {"cat": "Gynäkologische Onkologie", "q": "Was ist neu am FIGO-2018-Staging des Zervixkarzinoms?", "a": "Stadium IIIC neu: IIIC1 = pelvine LK-Metastasen, IIIC2 = paraaortale LK-Metastasen. r/p-Notation (r = Bildgebung, p = Pathologie). Stadium I: IA1 (≤3mm), IA2 (>3–5mm), IB1 (≤2cm), IB2 (>2–4cm), IB3 (>4cm).", "id": 257}, {"cat": "Gynäkologische Onkologie", "q": "Was definiert Stadium IV beim Ovarialkarzinom?", "a": "IVA: Pleuraerguss mit positiver Zytologie. IVB: Leber-/Milzparenchymmetastasen, extraabdominale Metastasen, transmurale Darmbeteiligung.", "id": 258}, {"cat": "Gynäkologische Onkologie", "q": "Was ist das neue FIGO-2023-Staging beim Endometriumkarzinom?", "a": "Integration molekularer Subtypen: POLE-Mutation → Downstaging zu IAmPOLE (günstigste Prognose). p53-Aberration → Upstaging. Stadium IA3: low-grade endometrioides CA mit Uterus + Ovar (synchron, günstig).", "id": 259}, {"cat": "Gynäkologische Onkologie", "q": "Welche vier molekularen Subtypen des Endometriumkarzinoms gibt es?", "a": "POLE-mutiert (beste Prognose), MSI-H/MMR-defizient, Copy-number-low/p53-Wildtyp, Copy-number-high/p53-abnormal (schlechteste Prognose).", "id": 260}, {"cat": "Gynäkologische Onkologie", "q": "Was ist das Standardchemotherapie-Regime beim fortgeschrittenen Ovarialkarzinom?", "a": "Carboplatin AUC 5–6 + Paclitaxel 175 mg/m² i.v. alle 3 Wochen × 6 Zyklen.", "id": 261}, {"cat": "Gynäkologische Onkologie", "q": "Was zeigte die SOLO-1-Studie zum Ovarialkarzinom?", "a": "Olaparib-Maintenance bei BRCA-mutiertem Ovarialkarzinom: 70% niedrigeres Progressionsrisiko. 7-Jahres-OS: 67% vs. 46,5% (Placebo).", "id": 262}, {"cat": "Gynäkologische Onkologie", "q": "Was ist die Erstlinientherapie beim fortgeschrittenen Endometriumkarzinom?", "a": "Carboplatin/Paclitaxel + Immuntherapie (Pembrolizumab oder Dostarlimab) für Stadium III–IV (Kategorie 1 NCCN).", "id": 263}, {"cat": "Gynäkologische Onkologie", "q": "Was zeigte die GY018-Studie beim Endometriumkarzinom?", "a": "Pembrolizumab + Carbo/Pac: bei MMR-D medianes PFS nicht erreicht vs. 7,6 Monate (HR 0,30). Bei MMR-P: 13,1 vs. 8,7 Monate (HR 0,54).", "id": 264}, {"cat": "Gynäkologische Onkologie", "q": "Was ist die Erstlinientherapie beim metastasierten Zervixkarzinom?", "a": "Platin + Paclitaxel + Bevacizumab (GOG 240). Bei PD-L1+ (CPS ≥1): + Pembrolizumab (KEYNOTE-826). OS-Vorteil Bev: 17,0 vs. 13,3 Monate.", "id": 265}, {"cat": "Gynäkologische Onkologie", "q": "Was ist CA-125 und wann ist es erhöht?", "a": "Glykoprotein, erhöht bei 80% der epithelialen Ovarialkarzinome (nur 50% im Stadium I). Auch erhöht bei: Endometriose, Schwangerschaft, PID, Niereninsuffizienz. Normwert: 35 U/mL.", "id": 266}, {"cat": "Gynäkologische Onkologie", "q": "Was ist HE4 und welche Vorteile hat es?", "a": "Human Epididymis Protein 4. Höhere Spezifität als CA-125 (8% vs. 29% falsch-positiv). Besonders bei prämenopausalen Frauen. ROMA-Score kombiniert CA-125 + HE4 + Menopausenstatus.", "id": 267}, {"cat": "Gynäkologische Onkologie", "q": "Welche Tumormarker bei Keimzelltumoren?", "a": "AFP (Dottersacktumor), β-hCG (Chorionkarzinom, Dysgerminom), LDH (Dysgerminom, korreliert mit Tumorlast).", "id": 268}, {"cat": "Gynäkologische Onkologie", "q": "Was ist das BEP-Schema?", "a": "Bleomycin + Etoposid + Cisplatin. Standard bei malignen Keimzelltumoren des Ovars. 3 Zyklen (good risk) oder 4 Zyklen (poor risk).", "id": 269}, {"cat": "Gynäkologische Onkologie", "q": "Welche PARP-Inhibitoren werden beim Ovarialkarzinom eingesetzt?", "a": "Olaparib, Niraparib, Rucaparib – als Maintenance nach CR/PR auf platinbasierte Therapie. Besonders wirksam bei BRCA-Mutation und HRD-positivem Status.", "id": 270}, {"cat": "Gynäkologische Onkologie", "q": "Was ist Mirvetuximab Soravtansin?", "a": "Antikörper-Wirkstoff-Konjugat gegen FRα. Zugelassen für platinresistentes Ovarialkarzinom mit FRα-Expression ≥75%.", "id": 271}, {"cat": "Gynäkologische Onkologie", "q": "Welche Chemotherapie beim platinresistenten Ovarialkarzinom-Rezidiv?", "a": "Liposomales Doxorubicin ± Bevacizumab, wöchentliches Paclitaxel ± Bev, Topotecan ± Bev, Gemcitabin, Docetaxel.", "id": 272}, {"cat": "Gynäkologische Onkologie", "q": "Was ist die Bedeutung von MMR-IHC beim Endometriumkarzinom?", "a": "Empfohlen für alle Fälle. Sensitivität 96%, Spezifität 95% für MSI. Identifiziert Lynch-Syndrom-Kandidatinnen, informiert Immuntherapie-Entscheidungen.", "id": 273}, {"cat": "Kontrazeption", "q": "Was ist der Pearl-Index und wie wird er berechnet?", "a": "Anzahl Schwangerschaften pro 100 Frauenjahre (= Anwendungsjahre). Unterschieden: 'perfect use' vs. 'typical use'. Je niedriger, desto effektiver.", "id": 274}, {"cat": "Kontrazeption", "q": "Wie hoch ist der Pearl-Index bei KOK (typische Anwendung)?", "a": "Ca. 4–9 Schwangerschaften pro 100 Frauenjahre (typical use). Perfect use: ~0,3. Bei Adoleszenten ca. doppelt so hoch.", "id": 275}, {"cat": "Kontrazeption", "q": "Wie hoch ist der Pearl-Index bei LARC-Methoden?", "a": "~0,27 pro 100 Frauenjahre (CHOICE-Studie). Vergleichbar mit Sterilisation. Ca. 20× effektiver als Pille bei typical use.", "id": 276}, {"cat": "Kontrazeption", "q": "Wie hoch ist der Pearl-Index beim Kupfer-IUD?", "a": "0,7% im ersten Jahr. Wirkdauer bis 10 Jahre. Effektivste nicht-hormonale Langzeitmethode.", "id": 277}, {"cat": "Kontrazeption", "q": "Wie hoch ist der Pearl-Index beim LNG-IUD (Mirena)?", "a": "0,14% im ersten Jahr. Wirkdauer mindestens 7 Jahre. Gleichzeitig Therapie bei Menorrhagie.", "id": 278}, {"cat": "Kontrazeption", "q": "Wie hoch ist der Pearl-Index beim Etonogestrel-Implantat (Nexplanon)?", "a": "0,001% – niedrigste Versagensrate aller reversiblen Methoden. Wirkdauer bis 5 Jahre.", "id": 279}, {"cat": "Kontrazeption", "q": "Wie hoch ist der Pearl-Index bei Barrieremethoden?", "a": "Kondom typical use: 18%. Diaphragma: 12–28%. Spermizide allein: 28%. Perfekte Anwendung deutlich besser.", "id": 280}, {"cat": "Kontrazeption", "q": "Was ist das Vorgehen bei 1 vergessener KOK-Pille (bis 48h)?", "a": "Pille sofort nachnehmen, restliche zur gewohnten Zeit. Keine Backup-Methode nötig.", "id": 281}, {"cat": "Kontrazeption", "q": "Was ist das Vorgehen bei ≥2 vergessenen KOK-Pillen (≥48h)?", "a": "Letzte vergessene Pille sofort nehmen, restliche verwerfen. Weiter zur gewohnten Zeit. Backup für 7 Tage. Notfallkontrazeption erwägen wenn Vergessen in Woche 1 + ungeschützter GV.", "id": 282}, {"cat": "Kontrazeption", "q": "Was ist die Sonderregel bei vergessenen Pillen in Woche 3?", "a": "Hormonfreies Intervall überspringen und direkt neuen Blister beginnen. Backup für 7 Tage (keine Abbruchblutung in diesem Zyklus).", "id": 283}, {"cat": "Kontrazeption", "q": "Was ist das Vorgehen bei Erbrechen/Durchfall innerhalb von 3–4h nach Pilleneinnahme?", "a": "Wie eine vergessene Pille behandeln. Bei schwerem Erbrechen ≥48h: Backup für 7 Tage.", "id": 284}, {"cat": "Kontrazeption", "q": "Was ist das Vorgehen bei vergessener Minipille (Norethisteron) >3h verspätet?", "a": "Pille sofort nachnehmen. Backup für 2 Tage. Notfallkontrazeption erwägen bei kürzlichem ungeschütztem GV.", "id": 285}, {"cat": "Kontrazeption", "q": "Was ist die Desogestrel-Minipille (Cerazette) und wie ist sie bei Vergessen?", "a": "12-Stunden-Toleranzfenster (vs. 3h Norethisteron). Wirkungsmechanismus: Hemmung der Ovulation (bei 97% der Zyklen). Bei >12h Vergessen: wie Norethisteron vorgehen.", "id": 286}, {"cat": "Kontrazeption", "q": "Welche absoluten Kontraindikationen (WHO 4) hat die KOK?", "a": "Schwere kardiovaskuläre Erkrankungen, VTE/Schlaganfall in Anamnese, Migräne mit Aura, aktive Lebererkrankung, Brustkrebs, Stillzeit <6 Wochen postpartum. Systolischer BD ≥160 mmHg.", "id": 287}, {"cat": "Kontrazeption", "q": "Welche Kontraindikationen hat das Kupfer-IUD?", "a": "Aktive STI/PID, ungeklärte vaginale Blutung, Uterus-Anomalien (myombedingte Kavitätsverformung), Wilson-Krankheit (relative KI). Vorherige EUG ist keine KI.", "id": 288}, {"cat": "Kontrazeption", "q": "Welche Kontraindikationen hat das Hormon-IUD (Mirena)?", "a": "Aktive STI/PID, ungeklärte Blutung, Brustkrebs (relativ), schwere Lebererkrankung. Häufigste Nebenwirkung: Metrorrhagie in ersten 3–6 Monaten.", "id": 289}, {"cat": "Kontrazeption", "q": "Was ist das WHO-Klassifikationssystem für Kontrazeption?", "a": "WHO 1: keine Einschränkung. WHO 2: Vorteile überwiegen Risiken. WHO 3: Risiken überwiegen Vorteile. WHO 4: absolute Kontraindikation.", "id": 290}, {"cat": "Kontrazeption", "q": "Was ist die Notfallkontrazeption und welche Optionen gibt es?", "a": "Levonorgestrel 1,5mg (bis 72h), Ulipristalacetat 30mg (bis 120h), Kupfer-IUD (bis 120h, effektivstes Mittel >99%).", "id": 291}, {"cat": "Kontrazeption", "q": "Wann ist nach einer KOK-freien Phase sofortiger Schutz vorhanden?", "a": "Wenn KOK in den ersten 5 Tagen des Zyklus begonnen wird: sofortiger Schutz. Später begonnen: Backup für 7 Tage. Außer: Minipille (sofortiger Schutz wenn in ersten 5 Tagen begonnen).", "id": 292}, {"cat": "Reproduktionsmedizin & Recht CH", "q": "Was sind IVF-Protokolle und welche werden unterschieden?", "a": "Langes GnRH-Agonisten-Protokoll (Downregulation, dann Stimulation), kurzes GnRH-Antagonisten-Protokoll (simultane Gabe während Stimulation). Antagonisten: weniger OHSS-Risiko, bevorzugt bei OHSS-Risiko.", "id": 293}, {"cat": "Reproduktionsmedizin & Recht CH", "q": "Was ist die Lutealphaseunterstützung bei IVF?", "a": "Progesteron (vaginal, i.m. oder oral): z.B. Utrogest 600mg/Tag vaginal oder Crinone 8%. Beginn nach Oozytenretrieval. Dauer bis 10.–12. SSW bei positiven hCG.", "id": 294}, {"cat": "Reproduktionsmedizin & Recht CH", "q": "Was ist Stimulation mit Gonadotropinen beim Corpus-luteum-Defekt?", "a": "Dopaminerge Stimulation (Cabergolin) bei Hyperprolaktinämie, Gonadotropine (rFSH, hMG) bei hypogonadotropem Hypogonadismus, Clomifen/Letrozol bei normogonadotroper Anovulation.", "id": 295}, {"cat": "Reproduktionsmedizin & Recht CH", "q": "Was ist die TESE (testikuläre Spermienextraktion)?", "a": "Chirurgische Gewinnung von Spermien aus Hodengewebe bei Azoospermie. Indikation für ICSI. Erfordert vorherige genetische Abklärung (Karyotyp, AZF-Deletion).", "id": 296}, {"cat": "Reproduktionsmedizin & Recht CH", "q": "Was ist der Unterschied zwischen homologer und heterologer Insemination?", "a": "Homolog: Spermien vom Partner. Heterolog: Samenspende. In CH: Samenspende erlaubt für eingetragene Paare, Kind hat Recht auf Abstammungskenntnis ab 18 Jahren.", "id": 297}, {"cat": "Reproduktionsmedizin & Recht CH", "q": "Was ist Hysterosalpingographie (HSG) und was diagnostiziert sie?", "a": "Röntgenkontrastdarstellung der Tube zur Prüfung der Durchgängigkeit. Erste diagnostische Massnahme bei Sterilität. Cave: Infektionsrisiko, nicht ungefährlich bei geschlossenen Tuben.", "id": 298}, {"cat": "Reproduktionsmedizin & Recht CH", "q": "Was ist der Unterschied zwischen primärer und sekundärer Infertilität?", "a": "Primär: noch keine Schwangerschaft trotz ≥12 Monate regelmässigem ungeschütztem GV. Sekundär: trotz vorheriger Schwangerschaft keine neue Konzeption.", "id": 299}, {"cat": "Reproduktionsmedizin & Recht CH", "q": "Was ist die Abklärung beim infertilen Mann?", "a": "Spermiogramm (Normwerte WHO 2021): Konzentration ≥16 Mio/ml, Motilität ≥42% (progressiv ≥30%), Morphologie ≥4% normal. Karyotyp, FSH, LH, Testosteron, AZF-Deletion bei Azoospermie.", "id": 300}, {"cat": "Reproduktionsmedizin & Recht CH", "q": "Was sind Normwerte des Spermiogramms nach WHO 2021?", "a": "Konzentration ≥16 Mio/ml, Gesamtmotilität ≥42%, progressive Motilität ≥30%, normale Morphologie ≥4%, Volumen ≥1,4 ml.", "id": 301}, {"cat": "Reproduktionsmedizin & Recht CH", "q": "Was ist eine IUI (intrauterine Insemination)?", "a": "Einbringung aufbereiteter Spermien in den Uterus. Indikation: leichte männliche Infertilität, zervikaler Faktor, unerklärte Infertilität. Erfolgsrate ca. 10–15% pro Zyklus.", "id": 302}, {"cat": "Geburtshilfe", "q": "Was ist IUGR und wie wird es nach Delphi-Konsensus diagnostiziert?", "a": "IUGR frühes Onset (<32 SSW): PE/BA <3. Perz. ODER diastolische Null/Reverse Flow ODER PE/BA <10. Perz + Doppler-Anomalie. Spätes Onset (≥32 SSW): PE/BA <3. Perz. ODER ≥2 von: PE/BA <10 Perz., Wachstumsverlangsamung, CPI <5. Perz.", "id": 303}, {"cat": "Geburtshilfe", "q": "Was ist das Baby-Blues-Phänomen?", "a": "Vorübergehende Stimmungslabilität, Weinen, Stimmungsschwankungen in ersten 3–10 Tagen postpartum. 70–80% der Wöchnerinnen. Kein erhöhtes Langzeitrisiko. Keine spezifische Therapie, keine Trennung von Mutter und Kind.", "id": 304}, {"cat": "Geburtshilfe", "q": "Was ist postpartale Depression?", "a": "Anhaltende depressive Stimmung >2 Wochen pp. Prävalenz 10–15%. Edinburgh-Postnatal-Depression-Scale (EPDS) zum Screening. Therapie: Psychotherapie ± Antidepressiva. Kein Grund für Trennung Mutter-Kind.", "id": 305}, {"cat": "Geburtshilfe", "q": "Was ist Mastitis puerperalis und was ist die häufigste falsche Aussage?", "a": "Entzündung der Mamma meist in ersten 6 Wochen Stillzeit. Häufigster Erreger: Staphylococcus aureus (gram-positiv!), NICHT E. coli. Symptome: Schüttelfrost, Fieber, Tachykardie, rote schmerzhafte Brust.", "id": 306}, {"cat": "Geburtshilfe", "q": "Wie wird PPROM (Blasensprung <37 SSW) gemanagt?", "a": "Hospitalisierung, Abstriche, Infektionsparameter (CRP, Leukozyten). Steroidgabe 24–34 SSW. Antibiotika (Erythromycin für 10 Tage). GBS-Prophylaxe. Tokolyse für 48h zur Steroidgabe. Entbindung bei Chorioamnionitis.", "id": 307}, {"cat": "Geburtshilfe", "q": "Was ist das Vorgehen bei einer 32-jährigen III-Para in der 28. SSW nach Auffahrunfall?", "a": "CTG, Ultraschall, Blutgruppe und Rhesusfaktor, Bestimmung fetaler Erythrozyten im mütterlichen Blut (HbF) – alle 4 Massnahmen sinnvoll.", "id": 308}, {"cat": "Geburtshilfe", "q": "Was ist der Geburtsbeginndefinition?", "a": "Auftreten regelmässiger, portiowirksamer Wehen (nicht: erste Kontraktionen, Blasensprung, Zeichnung oder Tiefertreten des Kindsteils).", "id": 309}, {"cat": "Geburtshilfe", "q": "Was sind Komplikationen bei Zwillingsgeburt?", "a": "Vorzeitige Plazentalösung nach Geburt Zwilling A, Nabelschnurvorfall, akutes TTTS, fetale Asphyxie, Schulterdystokie. Zwilling B: häufiger vaginal-operative oder Sectio-Entbindung.", "id": 310}, {"cat": "Geburtshilfe", "q": "Was ist Aspirationsgefahr unter Anästhesie in der Schwangerschaft?", "a": "Gefürchtet: Aspiration von Magensaft (Mendelson-Syndrom). Mageninhalt in SS ist saurer. Massnahmen: Nüchternheit, Rapid-Sequence-Induction (RSI), Krikoiddruck. Cave: erhöhtes Aspirationsrisiko.", "id": 311}, {"cat": "Geburtshilfe", "q": "Alkohol während der Schwangerschaft: Was ist die korrekte Aussage?", "a": "In grossen Mengen Ursache des fetalen Alkoholsyndroms (spezifisches Missbildungssyndrom). In kleinen Mengen wahrscheinlich ungefährlich, aber kein sicherer Grenzwert bekannt → Abstinenz empfohlen.", "id": 312}, {"cat": "Geburtshilfe", "q": "Was ist die Hysterosalpingographie und ist sie erste Massnahme bei Sterilität?", "a": "HSG erlaubt Nachweis der Tubendurchgängigkeit. Erste Massnahme bei Sterilität ist RICHTIG. Cave: HSG ist nicht absolut ungefährlich und bei geschlossenen Tuben können weitere Massnahmen trotzdem überflüssig sein (falsche Begründung).", "id": 313}, {"cat": "PCOS & Endokrinologie", "q": "Was ist das adrenogenitale Syndrom (AGS)?", "a": "21-Hydroxylase-Mangel (90%): Kortisolsynthesestörung → Androgen-Überschuss. Klinisch: Virilisierung NG, Pseudohermaphroditismus femininus, Salzverlustsyndrom. Therapie: Hydrokortison.", "id": 314}, {"cat": "PCOS & Endokrinologie", "q": "Was ist bei AGS mit Hydrokortison bei fieberhafter Erkrankung zu beachten?", "a": "Kortisondosis muss erhöht werden (verdoppeln/verdreifachen). Glukokortikoide hemmen die Infektabwehr NICHT – falsch. Tatsächlich: AGS-Patienten brauchen unter Stress mehr Kortisol.", "id": 315}, {"cat": "PCOS & Endokrinologie", "q": "Was ist eine biphasische Basaltemperaturkurve und wann fehlt sie?", "a": "Anstieg um 0,2–0,5°C nach Ovulation durch Progesteron. Fehlt bei: Turner-Syndrom (keine Ovulation), Swyer-Syndrom, Androgen-Insensitivitäts-Syndrom. Nicht: Hypo-/Hyperparathyreoidismus.", "id": 316}, {"cat": "PCOS & Endokrinologie", "q": "Was ist die häufigste Ursache der sekundären Dysmenorrhoe?", "a": "Endometriose (häufigste Ursache). Weitere: Adenomyosis uteri, Myome, Zervikalstenose, IUD. Primäre Dysmenorrhoe: Prostaglandine ohne organische Ursache.", "id": 317}, {"cat": "PCOS & Endokrinologie", "q": "Welche 25-jährige Patientin mit Oligomenorrhoe und leichter Hyperprolaktinämie – was ist Erstlinientherapie bei Kinderwunsch?", "a": "Dopaminagonist (Cabergolin/Bromocriptin) zur Prolaktin-Normalisierung und Ovulationswiederherstellung. Nicht: KOK, GnRH-Agonist.", "id": 318}, {"cat": "PCOS & Endokrinologie", "q": "Was ist die Therapie bei Turner-Syndrom?", "a": "HRT ab Pubertätsalter (Östrogen-Gestagen) zur Pubertätsinduktion und Langzeit-Östrogenisierung. Wachstumshormon (GH) für Wachstum. Keine Fertilität möglich (Eizellspende in CH erlaubt).", "id": 319}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was ist kongenitale Uterusaplasie und bei welchem Syndrom tritt sie auf?", "a": "Beim Rokitansky-Küster-Syndrom (MRKH). Nicht beim Klinefelter-Syndrom, Turner-Syndrom, AGS. MRKH: 46,XX, normale Ovarien, keine Vagina/Uterus.", "id": 320}, {"cat": "Fehlbildungen & Neonatologie", "q": "Welche Fehlbildung wird beim Turner-Syndrom (45 X0) häufig gefunden?", "a": "Aortenisthmusstenose (häufigste kardiovaskuläre Fehlbildung, ~35%), nicht Vaginalaplasie oder Lungenhypoplasie.", "id": 321}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was ist Pubertas praecox (ausser) – was ist KEINE Ursache?", "a": "Alle sind Ursachen AUSSER Hyperthyreose (Hyperthyreose = keine typische Ursache). Ursachen: NNR-Tumor, Erkrankungen im Thalamusbereich, exogene Hormonzufuhr, Granulosazelltumor.", "id": 322}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was ist eine 2 Tage altes NG mit Atemnotsyndrom, Erbrechen, kein Mekonium, Herzfrequenz 152/min, Mediastinalshift links – Diagnose?", "a": "Zwerchfellhernie (Diaphragmatic hernia). Röntgen: Darmschlingen im Thorax, Mediastinalshift zur kontralateralen Seite.", "id": 323}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was ist das Oligohydramnion nicht assoziiert mit?", "a": "Mehrlingsschwangerschaft, Diabetes mellitus, Ösophagusatresie sind NICHT assoziiert. Assoziiert mit: fetale Nierenagenesie, IUGR, PPROM, Blasenauslassobstruktion.", "id": 324}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was ist das Tokoplasma-Screening in der Schweiz?", "a": "Nicht mehr empfohlen in CH. Begründung: zu selten, Therapie kommt meist zu spät. Primärprävention (kein rohes Fleisch, keine Katzenfaeces) effektiver. Nicht: Toxoplasma wird durch Rohmilch übertragen (falsch).", "id": 325}, {"cat": "Statistik & Studiendesign", "q": "In einer Studie werden 50 Frauen behandelt um eine Komplikation zu verhindern, was ist das?", "a": "Die NNT (Number Needed to Treat) beträgt 50. Das absolute Risiko ist reduziert um 1/50 = 2%. NNT = 1/ARR.", "id": 326}, {"cat": "Statistik & Studiendesign", "q": "Eine randomisierte australische Studie zeigt 3% vs. 1% perinatale Komplikationen. Welche Behauptung ist richtig?", "a": "Der Effekt der Behandlung kann quantifiziert werden mittels eines relativen Risikos von 0,2 (= 1/5). Die Differenz absoluter Risiken beträgt 66%. Nicht: auf uns übertragbar (andere Population).", "id": 327}, {"cat": "Statistik & Studiendesign", "q": "Was ist ein positiv prädiktiver Wert von 6%?", "a": "Wenn AFP-Test bei Spina bifida positiv ist: von 100 positiven Tests haben nur 6 tatsächlich eine Spina bifida. Beispiel: Inzidenz 2:1000, Sensitivität 75%, Falsch-Positiv-Rate 3%.", "id": 328}, {"cat": "Statistik & Studiendesign", "q": "Was ist der Unterschied zwischen einem prospektiven und retrospektiven Studiendesign?", "a": "Prospektiv: Daten werden von Beginn an gesammelt (z.B. RCT, Kohortenstudie). Retrospektiv: Daten bereits vorhanden, rückwärtsblickend (z.B. Fall-Kontroll-Studie). RCT hat höchsten Evidenzgrad.", "id": 329}, {"cat": "Endometriose", "q": "Was ist die rASRM-Klassifikation der Endometriose?", "a": "Stadien I–IV basierend auf Ausdehnung und Tiefe der Läsionen, Vorhandensein von Adhäsionen und Endometriomen. Stadium I/II: minimal/mild. Stadium III/IV: moderat/schwer. Kein direkter Zusammenhang mit Schmerz oder Infertilität.", "id": 330}, {"cat": "Endometriose", "q": "Was ist der Unterschied zwischen peritonealer, ovarieller und tief infiltrierender Endometriose?", "a": "Peritoneal: oberflächliche Herde auf Peritoneum. Ovariell: Endometriome (Schokoladenzysten). Tief infiltrierend (DIE): >5 mm Tiefe, befällt Darm, Blase, Ureteren, Scheide.", "id": 331}, {"cat": "Endometriose", "q": "Was ist Adenomyosis uteri?", "a": "Endometriumdrüsen und -stroma im Myometrium. Symptome: Dysmenorrhoe, Hypermenorrhoe, vergrösserter Uterus. Diagnose: TVUS (inhomogenes Myometrium, Zysten) oder MRT. Therapie: LNG-IUS, GnRH-Analoga, Hysterektomie.", "id": 332}, {"cat": "Endometriose", "q": "Was sind typische Symptome der Adenomyosis?", "a": "Dysmenorrhoe (häufigste), Hypermenorrhoe, Menorrhagie, chronische Unterbauchschmerzen, Dyspareunie. Uterus symmetrisch vergrössert und druckdolent.", "id": 333}, {"cat": "Endometriose", "q": "Welche Endometriose-Therapie ist gleichzeitig kontrazeptiv?", "a": "Alle hormonellen Therapien: KOK, Gestagene (Dienogest, Desogestrel), GnRH-Analoga, LNG-IUS. Ausnahme: NSAR (nicht kontrazeptiv, nur Schmerztherapie).", "id": 334}, {"cat": "Endometriose", "q": "Was ist Dienogest und warum wird es bei Endometriose eingesetzt?", "a": "Gestagen mit starker lokaler antiproliferativer Wirkung auf Endometrioseherde. Führt zu Amenorrhoe oder Spotting. Gut verträglich, ohne starke Hypöstrogenisierung. Dauertherapie möglich.", "id": 335}, {"cat": "Endometriose", "q": "Was ist die Rolle von GnRH-Agonisten bei Endometriose?", "a": "Erstlinie bei schwerer Endometriose wenn KOK/Gestagene insuffizient. Führt zu medikamentöser Menopause. Cave: Knochendichteverlust → Add-back-Therapie obligat ab 3–6 Monate. Maximaldauer 6–12 Monate.", "id": 336}, {"cat": "Endometriose", "q": "Was ist der Unterschied zwischen GnRH-Agonisten und -Antagonisten bei Endometriose?", "a": "Agonisten: initial Flare-up (1–2 Wochen), dann Downregulation. Antagonisten: sofortige Hormonunterdrückung, kein Flare-up, kurze Halbwertszeit. Antagonisten bevorzugt bei OHSS-Risiko.", "id": 337}, {"cat": "Endometriose", "q": "Was ist die Rolle der Laparoskopie bei Endometriose?", "a": "Goldstandard für Diagnose (Biopsie) und Therapie. Koagulation/Exzision peritonealer Herde, Zystektomie (Endometriome), Adhäsiolyse. Rezidivrate nach Op: 20–50% nach 5 Jahren.", "id": 338}, {"cat": "Endometriose", "q": "Was sind Kontraindikationen für Endometriose-Operation?", "a": "Keine absoluten Kontraindikationen, aber relative: schlechter AZ, komplizierter Darm-/Blasenbefall (Spezialist nötig), junges Alter (Rezidivrisiko hoch). Immer: fertilitätserhaltende Op bevorzugen.", "id": 339}, {"cat": "Endometriose", "q": "Was ist das Fitz-Hugh-Curtis-ähnliche Bild bei Endometriose?", "a": "Bei tief infiltrierender Endometriose können Verwachsungen entstehen (Violinensaiten-Verwachsungen im Douglas). Ähnelt klinisch dem Fitz-Hugh-Curtis-Syndrom (Perihepatitis bei PID/Chlamydien).", "id": 340}, {"cat": "Endometriose", "q": "Welche Laborparameter sind bei Endometriose erhöht?", "a": "CA-125 kann erhöht sein (nicht spezifisch). Normal: keine spezifischen Blutmarker verfügbar. Diagnosesicherung nur durch Histologie (Biopsie).", "id": 341}, {"cat": "Endometriose", "q": "Was ist die Wirksamkeit von Aromatase-Inhibitoren bei Endometriose?", "a": "Drittlinientherapie (Letrozol, Anastrozol) bei therapierefraktärer Endometriose. Kombiniert mit Gestagen oder GnRH-Analogon. Cave: Knochendichteverlust.", "id": 342}, {"cat": "Endometriose", "q": "Was ist der optimale Zeitpunkt zur Op bei Endometriose vor IVF?", "a": "Umstritten. Kleine Endometriome (<4 cm): Op-Nutzen für IVF nicht belegt (Gefahr Ovarialreserve). Grosse Endometriome (>4 cm): Op erwägen. Individuelle Entscheidung.", "id": 343}, {"cat": "Endometriose", "q": "Welche Komplikationen hat eine Zystektomie eines Endometrioms?", "a": "Reduktion der Ovarialreserve (AMH sinkt nach Op), Rezidivrisiko ~30% nach 5 Jahren. Daher: zurückhaltend bei jungen Frauen ohne abgeschlossene Familienplanung.", "id": 344}, {"cat": "Endometriose", "q": "Was ist das Aktivationsmodell der Endometriose?", "a": "Retrograde Menstruation (Sampson-Theorie): Endometriumzellen gelangen durch Tuben ins Peritoneum. Nicht alle Frauen mit retrograder Menstruation entwickeln Endometriose → Immunfaktoren entscheidend.", "id": 345}, {"cat": "Endometriose", "q": "Was ist Endometriose-assoziierte Infertilität und wie wird sie behandelt?", "a": "Mechanisch (Adhäsionen, Tubenschaden), immunologisch (veränderte peritoneale Umgebung), endokrin. Therapie: Laparoskopische Sanierung, danach IVF wenn konservativ insuffizient.", "id": 346}, {"cat": "Endometriose", "q": "Was ist typisch im MRT bei tief infiltrierender Endometriose?", "a": "Hypointense noduläre Läsionen auf T2-gewichteten Bildern ('dark nodules'). Erlaubt Beurteilung von Darm, Blase, Parametrien. Überlegenheit gegenüber Ultraschall bei DIE.", "id": 347}, {"cat": "Endometriose", "q": "Was ist die Prävalenz von Endometriose bei infertilen Frauen?", "a": "30–50% (vs. ~10% in der Allgemeinbevölkerung). Bei Frauen mit chronischen Beckenschmerzen: bis 80%.", "id": 348}, {"cat": "Endometriose", "q": "Welche Aussage über Endometriose stimmt nicht?", "a": "Die Grösse der Endometrioseherde korreliert NICHT mit dem Leidensdruck. Kleine Herde können starke Schmerzen verursachen, grosse Herde können asymptomatisch sein.", "id": 349}, {"cat": "Menopause & HRT", "q": "Was sind die STRAW+10-Stadien der Menopause?", "a": "Reproduktiv → Menopausal Transition (früh/spät) → Postmenopause (früh/spät). Transition: Zyklunregelmässigkeiten, FSH-Anstieg. Perimenopause = Transition + 12 Monate nach letzter Regel.", "id": 350}, {"cat": "Menopause & HRT", "q": "Was ist der Unterschied zwischen natürlicher und chirurgischer Menopause?", "a": "Natürlich: schrittweiser Hormonabfall. Chirurgisch (beidseitige Oophorektomie): abrupter Östrogenmangel → schwerere Symptome, höheres kardiovaskuläres Risiko, ausgeprägterer Knochenverlust. HRT dringlicher indiziert.", "id": 351}, {"cat": "Menopause & HRT", "q": "Was ist das genitourinäre Menopausensyndrom (GSM)?", "a": "Vulvovaginale Atrophie + Harnwegssymptome durch Östrogenmangel. Symptome: Trockenheit, Dyspareunie, Dysurie, Harnwegsinfektionen. Therapie: lokales Östrogen (Estriol-Creme, Vaginalring, Östriol-Ovula).", "id": 352}, {"cat": "Menopause & HRT", "q": "Wie lange nach der Menopause sollte HRT begonnen werden für kardiovaskulären Schutz?", "a": "'Window of Opportunity': HRT wirkt kardiovaskulär protektiv wenn in den ersten 10 Jahren oder vor dem 60. LJ begonnen ('Timing Hypothesis'). Danach: kein Benefit, möglicherweise erhöhtes Risiko.", "id": 353}, {"cat": "Menopause & HRT", "q": "Was ist Tibolon und welche Wirkungen hat es?", "a": "Synthetisches Steroid mit östrogenen, gestagenen und androgenen Eigenschaften. Lindert Hitzewallungen, verbessert Libido, Osteoporoseprävention. Nicht für Frauen mit Brustkrebs in Anamnese.", "id": 354}, {"cat": "Menopause & HRT", "q": "Was ist Raloxifen und wann wird es eingesetzt?", "a": "SERM (selektiver Östrogenrezeptor-Modulator). Wirkung: Östrogenagonist an Knochen und Leber, Antagonist an Brust und Uterus. Indikation: Osteoporoseprävention postmenopausal. Cave: verstärkt Hitzewallungen.", "id": 355}, {"cat": "Menopause & HRT", "q": "Was ist die Prävention von Osteoporose in der Menopause?", "a": "Kalzium (1000–1200 mg/Tag) + Vitamin D (800–2000 IE/Tag), Bewegung (Kraft- und Ausdauertraining), Sturz- und Frakturprävention. Pharmakologisch: Bisphosphonate (Alendronat, Zoledronat), Denosumab, HRT, Raloxifen.", "id": 356}, {"cat": "Menopause & HRT", "q": "Was ist der Unterschied zwischen zyklischer und kontinuierlicher HRT?", "a": "Zyklisch: Östrogen kontinuierlich + Gestagen 12–14 Tage/Monat → monatliche Abbruchblutung. Kontinuierlich kombiniert: täglich Östrogen + Gestagen → Amenorrhoe (bevorzugt bei Frauen >1 Jahr postmenopausal).", "id": 357}, {"cat": "Menopause & HRT", "q": "Was ist der Zusammenhang zwischen HRT und Brustkrebs?", "a": "WHI-Studie: kombinierte Östrogen-Gestagen-HRT erhöht Brustkrebsrisiko nach 5+ Jahren (RR 1,26). Östrogen allein (bei Hysterektomie): kein erhöhtes Risiko. Risiko normalisiert sich nach Absetzen.", "id": 358}, {"cat": "Menopause & HRT", "q": "Was ist Osteoporose und wie wird sie diagnostiziert?", "a": "T-Score ≤-2,5 in DEXA-Messung (Knochendichtemessung). Osteopenie: T-Score -1,0 bis -2,5. Risikofaktoren: Östrogenmangel, Rauchen, Alkohol, Immobilität, Kortison-Dauertherapie.", "id": 359}, {"cat": "Menopause & HRT", "q": "Welche Vorteile hat HRT ausser Hitzewallungen?", "a": "Osteoporoseprävention, Linderung urogenitaler Atrophie, Verbesserung der Schlafqualität, Libidoverbesserung, möglicherweise kardiovaskulärer Schutz (Timing!), Reduktion von Typ-2-Diabetes.", "id": 360}, {"cat": "Menopause & HRT", "q": "Was sind typische Symptome des Klimakteriums?", "a": "Vasomotorisch: Hitzewallungen, Nachtschweiß. Urogenital: Trockenheit, Dyspareunie, Dysurie. Psychisch: Stimmungsschwankungen, Schlafstörungen, Vergesslichkeit. Somatisch: Gelenk-/Muskelschmerzen.", "id": 361}, {"cat": "Menopause & HRT", "q": "Bei welcher Erkrankung muss in der Postmenopause auf Östrogengabe verzichtet werden?", "a": "Mammakarzinom (absolute Kontraindikation). Auch: aktive VTE, Schlaganfall, koronare Herzkrankheit, aktive Lebererkrankung, Endometriumkarzinom.", "id": 362}, {"cat": "Menopause & HRT", "q": "Was ist der Unterschied zwischen bioidentischen und synthetischen Hormonen bei HRT?", "a": "Bioidentisch: chemisch identisch mit körpereigenen Hormonen (z.B. 17β-Östradiol, mikronisiertes Progesteron). Synthetisch: modifizierte Strukturen (z.B. konjugierte equine Östrogene, MPA). Bioidentische HRT wird bevorzugt.", "id": 363}, {"cat": "Menopause & HRT", "q": "Was ist Fezolinetant (Veoza)?", "a": "NK3-Rezeptor-Antagonist. Neues nicht-hormonales Medikament speziell für vasomotorische Symptome. Wirkt auf Hypothalamus-Thermoregulation. Alternative für Frauen mit HRT-Kontraindikationen (z.B. Brustkrebs).", "id": 364}, {"cat": "Menopause & HRT", "q": "Was ist das Klimakterium praecox (POI) und wie wird es therapiert?", "a": "Ovarialinsuffizienz vor 40. LJ. Amenorrhoe + FSH >25 IU/L. Therapie: HRT bis zum natürlichen Menopausenalter (50 J.) — nicht nur für Symptomkontrolle, sondern auch für Knochengesundheit und kardiovaskulären Schutz.", "id": 365}, {"cat": "Menopause & HRT", "q": "Was ist der FRAX-Score?", "a": "Fracture Risk Assessment Tool: berechnet 10-Jahres-Frakturrisiko basierend auf klinischen Risikofaktoren (Alter, BMI, Rauchen, Kortison, Sturzhäufigkeit, DEXA). Entscheidungshilfe für Bisphosphonat-Therapie.", "id": 366}, {"cat": "Menopause & HRT", "q": "Welcher Gestagen-Typ ist bei HRT mit geringerem Brustkrebsrisiko assoziiert?", "a": "Mikronisiertes Progesteron (Utrogest) hat laut E3N-Studie geringeres Brustkrebsrisiko als synthetische Gestagene (MPA, NETA). Daher bevorzugt bei HRT.", "id": 367}, {"cat": "Menopause & HRT", "q": "Brustschmerzen sind in der Menopause seltener — warum?", "a": "Brustschmerzen (Mastodynie) entstehen durch Östrogenspiegelschwankungen. In der Menopause fehlen diese Schwankungen → weniger Mastodynie. Nicht: die Brust reagiert nicht mehr auf Östrogen.", "id": 368}, {"cat": "Menopause & HRT", "q": "Was ist das Vaginalöstrogen und ist systemische Absorption relevant?", "a": "Niedrig-dosiertes vaginales Östrogen (Estriol): minimale systemische Absorption, keine Endometrium-Stimulation. Sicher auch bei KI für systemische HRT (z.B. nach Brustkrebs — unter Abwägung).", "id": 369}, {"cat": "Abnorme Blutung & Myome", "q": "Was ist der Unterschied zwischen Hypermenorrhoe, Menorrhagie und Metrorrhagie?", "a": "Hypermenorrhoe: zu starke Blutung (>80ml). Menorrhagie: verlängerte Blutung (>7 Tage). Metrorrhagie: unregelmässige azyklische Blutung. Menometrorrhagie: kombiniertees, unregelmässiges Muster.", "id": 370}, {"cat": "Abnorme Blutung & Myome", "q": "Was ist Adenomyosis uteri und wie unterscheidet sie sich von Endometriose?", "a": "Adenomyosis: Endometrium-Drüsen/Stroma IM Myometrium (intramural). Endometriose: ausserhalb Uterus (Peritoneum, Ovar). Beide können gleichzeitig auftreten. Adenomyosis: Uterus vergrössert, globulär.", "id": 371}, {"cat": "Abnorme Blutung & Myome", "q": "Wie werden Myome nach Lokalisation klassifiziert (FIGO-Klassifikation)?", "a": "Typ 0: gestielt submuköös. Typ 1: submuköös <50% intramural. Typ 2: submuköös ≥50% intramural. Typ 3: kontaktiert Endometrium. Typ 4: intramural. Typ 5–7: subserös. Typ 8: zervikale/parasitäre Myome.", "id": 372}, {"cat": "Abnorme Blutung & Myome", "q": "Welche Myome verursachen am häufigsten Blutungsstörungen?", "a": "Submuköse Myome (Typ 0–2) durch direkte Endometrium-Beeinflussung. Intramurale Myome können ebenfalls Blutungen verursachen. Subseröse Myome: meist Bulk-Symptome, selten Blutung.", "id": 373}, {"cat": "Abnorme Blutung & Myome", "q": "Was ist die Saline-Infusions-Sonohysterographie (SIS)?", "a": "Ultraschall mit intrakavitärer Kochsalzinfusion zur Darstellung der Uteruskavität. Besser als TVUS zur Detektion intrakavitärer Pathologien (Polypen, submuköse Myome). Alternative zur Hysteroskopie.", "id": 374}, {"cat": "Abnorme Blutung & Myome", "q": "Was ist der Unterschied zwischen Hysteroskopie und Kürettage?", "a": "Hysteroskopie: direkte Visualisierung der Uterushöhle + gezielte Biopsie. Kürettage: blind, geringere Sensitivität für fokale Läsionen. Fraktionierte Kürettage: erst Zervikalkanal, dann Korpus. HSK immer bevorzugt.", "id": 375}, {"cat": "Abnorme Blutung & Myome", "q": "Was ist die endoskopische Myomresektion (Hysteroskopische Myomektomie)?", "a": "Für submuköse Myome Typ 0–2 geeignet. Verbesserung der Fertilität bei submukösen Myomen nachgewiesen. Ambulant möglich. Rezidivrate geringer als bei abdominaler Myomektomie.", "id": 376}, {"cat": "Abnorme Blutung & Myome", "q": "Was ist die Tranexamsäure und wann wird sie eingesetzt?", "a": "Antifibrinolytikum: hemmt Plasminogenaktivierung → weniger Blutung. Nicht-hormonale Option bei Menorrhagie. Reduziert Blutverlust um ~50%. Nicht kontrazeptiv. Kurzzeitanwendung (nur während Menstruation).", "id": 377}, {"cat": "Abnorme Blutung & Myome", "q": "Was ist die Endometriumablation?", "a": "Thermische/elektrische Zerstörung des Endometriums (keine Kavitätskontrolle). Indikation: Menorrhagie ohne Kinderwunsch. Erfolgsrate: 80% Zufriedenheit nach 2 Jahren. Amenorrhoe bei 20–30%. Cave: Kinderwunsch danach kontraindiziert.", "id": 378}, {"cat": "Abnorme Blutung & Myome", "q": "Was ist GnRH-Antagonist (Relugolix) bei Myomen?", "a": "Oraler GnRH-Antagonist kombiniert mit Add-back (Östradiol + Norethindronacetat). Reduktion Menstruationsblutung und Myomvolumen. Zugelassen für bis zu 24 Monate. Vorteil vs. Agonist: kein Flare-up, orale Einnahme.", "id": 379}, {"cat": "Abnorme Blutung & Myome", "q": "Was ist das Asherman-Syndrom?", "a": "Intrauterine Synechien nach Kürettage (Abrasio), Myomektomie oder Infektion. Symptome: Hypomenorrhoe/Amenorrhoe, Sterilität, Fehlgeburten. Diagnose: Hysteroskopie. Therapie: hysteroskopische Synechiolyse + Östrogen postoperativ.", "id": 380}, {"cat": "Abnorme Blutung & Myome", "q": "Wiederholte 5–6-tägige Schmierblutungen vor der Menstruation bei einer 40-jährigen?", "a": "Corpus-luteum-Insuffizienz (häufigste Ursache). Diagnostik: Progesteron in der Lutealphase messen. Ursachen: PCOS, Hyperprolaktinämie, Adipositas. Therapie: Gestagen in der 2. Zyklushälfte.", "id": 381}, {"cat": "Abnorme Blutung & Myome", "q": "Was ist die diagnostische Abklärung bei postmenopausaler Blutung?", "a": "Immer abklären! Erstdiagnostik: TVUS (Endometriumdicke). Endometrium ≤3–4mm bei postmenopausalen Frauen ohne HRT: Malignität sehr unwahrscheinlich. ≥4mm: Hysteroskopie + Biopsie. Cave: auch bei dünnem Endometrium Malignität möglich.", "id": 382}, {"cat": "Abnorme Blutung & Myome", "q": "Was sind Risikofaktoren für Endometriumkarzinom?", "a": "Adipositas, Nulliparität, frühe Menarche/späte Menopause, PCOS, Tamoxifen, Lynch-Syndrom, Diabetes mellitus, unopponierte Östrogene. Schutztfaktor: Kontrazeptiva, Gestagene.", "id": 383}, {"cat": "Abnorme Blutung & Myome", "q": "Was ist die Therapie bei atypischer Endometriumhyperplasie?", "a": "Hysterektomie (definitive Therapie, Malignitätsrisiko 25–30% bei Atypie). Bei Kinderwunsch: Progesteron (Megestrolacetat, LNG-IUS) + engmaschige Kontrolle. Spontanremission möglich unter Progesteron.", "id": 384}, {"cat": "Abnorme Blutung & Myome", "q": "Was ist PALM-COEIN für die klinische Praxis?", "a": "Strukturierte Ursachensuche bei AUB. PALM = strukturell (Sonographie, Hysteroskopie). COEIN = nicht-strukturell (Labor: TSH, Gerinnung, Prolaktin; Zyklusanamnese). Schritt-für-Schritt-Abklärung.", "id": 385}, {"cat": "Abnorme Blutung & Myome", "q": "Was ist der LNG-IUS (Mirena) im Vergleich zur oralen Gestagen-Therapie?", "a": "LNG-IUS ist effektiver (Blutungsreduktion 80–90% vs. 30–50% oral). Wirkt lokal, kaum systemische Nebenwirkungen. Nebenwirkung: initiale Metrorrhagie (3–6 Monate), danach oft Amenorrhoe.", "id": 386}, {"cat": "Abnorme Blutung & Myome", "q": "Was ist das Polyhydramnion bei der Mutter von Bedeutung für Myome?", "a": "Kein Zusammenhang. Polyhydramnion: fetale Schluckstörung oder maternaler GDM. Myome: können Frühgeburt, Lageanomalien, Plazentaretention begünstigen.", "id": 387}, {"cat": "Abnorme Blutung & Myome", "q": "Welche Untersuchung ist bei Verdacht auf Endometriumkarzinom erste Wahl?", "a": "TVUS (transvaginale Sonographie): Endometriumdicke messen. Dann: Hysteroskopie + fraktionierte Kürettage für Histologie. Nicht: MRI als Erstdiagnostik (Staging, nicht Diagnose).", "id": 388}, {"cat": "Zervixkarzinom & Screening", "q": "Was ist die Transformationszone der Zervix?", "a": "Übergangsbereich zwischen Platten- und Zylinderepithel (Squamo-Columnar Junction, SCJ). Wichtigster Ort für CIN-Entstehung. Mit der Kolposkopie vollständig einsehbar = Typ 1. Nicht vollständig: Typ 2/3 → Konisation.", "id": 389}, {"cat": "Zervixkarzinom & Screening", "q": "Was ist die Kolposkopie und was wird beurteilt?", "a": "Vergrösserte Betrachtung der Portio mit Essigsäure und Lugol-Lösung. Beurteilung: Transformationszone, Acetoweiss-Areale, Mosaikmuster, Punktierung, atypische Gefässe. Gezielte Biopsie aus suspekten Arealen.", "id": 390}, {"cat": "Zervixkarzinom & Screening", "q": "Wie wird CIN (zervikale intraepitheliale Neoplasie) klassifiziert?", "a": "CIN 1: leichte Dysplasie (Koilozyten). CIN 2: moderate Dysplasie. CIN 3: schwere Dysplasie/Carcinoma in situ. LSIL entspricht meist CIN 1, HSIL entspricht CIN 2–3.", "id": 391}, {"cat": "Zervixkarzinom & Screening", "q": "Was ist das Management bei CIN 1?", "a": "Abwartend: spontane Regression bei 50–70% innerhalb 2 Jahren. Kontroll-Kolposkopie + Zytologie nach 6–12 Monaten. Therapie nur bei Persistenz >2 Jahre oder Progressionstendenz.", "id": 392}, {"cat": "Zervixkarzinom & Screening", "q": "Was ist das Management bei CIN 2–3?", "a": "Behandlung empfohlen: Loop Excision (LLETZ/LEEP) oder Konisation. Kryotherapie, Laservaporisation alternativ bei jungen Frauen mit CIN 2. Hysterektomie nur bei Versagen und abgeschlossener Familienplanung.", "id": 393}, {"cat": "Zervixkarzinom & Screening", "q": "Was ist LLETZ/LEEP?", "a": "Large Loop Excision of the Transformation Zone. Elektrochirurgische Schlingenexzision der Transformationszone. Diagnostisch und therapeutisch. Ambulant unter Lokalanästhesie. Risiko: Zervixinsuffizienz bei Frühgeburten.", "id": 394}, {"cat": "Zervixkarzinom & Screening", "q": "Was ist der Unterschied zwischen LEEP und Konisation?", "a": "LEEP: ambulant, Lokalanästhesie, flachere Exzision. Konisation (Messerkonisation): tiefer (endozervikale Läsionen), Vollnarkose, bessere histologische Auswertung. Bei unklarer Ausdehnung nach endozervikal: Konisation bevorzugt.", "id": 395}, {"cat": "Zervixkarzinom & Screening", "q": "Was ist Trachelektomie und wann wird sie eingesetzt?", "a": "Radikale Zervixentfernung mit Uteruserhalt. Indikation: Zervixkarzinom Stadium IA2–IB1 bei Kinderwunsch. Erfolgsrate: 70–80% Lebendgeburten möglich. Geringeres Rezidivrisiko als Konisation allein.", "id": 396}, {"cat": "Zervixkarzinom & Screening", "q": "Was ist das Management bei ASCUS (atypische Plattenepithelzellen unklarer Bedeutung)?", "a": "HPV-Triage: wenn HPV positiv → Kolposkopie. Wenn HPV negativ → Kontrolle in 3 Jahren. Kein sofortiger Behandlungsbedarf ohne Histologie.", "id": 397}, {"cat": "Zervixkarzinom & Screening", "q": "Was ist das Management bei ASCUS in der Schwangerschaft?", "a": "HPV-Triage + Kolposkopie (kein ECC = endozervikale Kürettage in SS!). Biopsie nur bei Verdacht auf Invasion. Keine Behandlung bis 6 Wochen post partum, dann Re-Evaluation.", "id": 398}, {"cat": "Zervixkarzinom & Screening", "q": "Welche HPV-Typen verursachen 70% aller Zervixkarzinome?", "a": "HPV 16 und 18 zusammen. HPV 16 vor allem bei Plattenepithelkarzinomen (50%), HPV 18 bei Adenokarzinomen (37%).", "id": 399}, {"cat": "Zervixkarzinom & Screening", "q": "Was sind Risikofaktoren für Zervixkarzinom?", "a": "HPV-Infektion (Hauptrisikofaktor), Rauchen, Immunsuppression (HIV), früher erster GV, viele Sexualpartner, orale Kontrazeptiva (schwach erhöht, diskutiert), Chlamydien-Koinfektion.", "id": 400}, {"cat": "Zervixkarzinom & Screening", "q": "Was ist das Adenokarzinom der Zervix und wie unterscheidet es sich vom Plattenepithelkarzinom?", "a": "Adenokarzinom: ~25% aller Zervixkarzinome, schwieriger im Pap-Abstrich zu erkennen (endozervikal), schlechtere Prognose. Plattenepithelkarzinom: ~75%, besser im Pap erkennbar, ektocervikal.", "id": 401}, {"cat": "Zervixkarzinom & Screening", "q": "Was ist der Nachweis von Treponema pallidum?", "a": "Dunkelfeldmikroskopie (direkter Nachweis aus Läsion), PCR, Latextest (weniger sensitiv), Nativ-Untersuchung. Serologie: treponemal (TPPA) + nicht-treponemal (VDRL/RPR).", "id": 402}, {"cat": "Zervixkarzinom & Screening", "q": "Was ist die Primärprävention des Zervixkarzinoms?", "a": "HPV-Impfung (vor erstem GV am wirksamsten). Sekundärprävention: regelmässiges Screening (Pap, HPV-Test). Tertiärprävention: frühzeitige Behandlung von CIN.", "id": 403}, {"cat": "Zervixkarzinom & Screening", "q": "Warum wurde Toxoplasmose-Screening in der Schweiz abgeschafft?", "a": "Zu selten um generelles Screening zu rechtfertigen. Therapie bei intrauteriner Infektion kommt meist zu spät. Primärprävention effektiver: kein rohes Fleisch, keine Katzenfaeces.", "id": 404}, {"cat": "Zervixkarzinom & Screening", "q": "Was ist die Hysterosalpingographie (HSG) bei Sterilität?", "a": "Erste Massnahme: richtig (Nachweis Tubendurchgängigkeit). Begründung 'ungefährlich bei geschlossenen Tuben' ist FALSCH. Wenn Tuben geschlossen: weitere Massnahmen (IVF) sind NICHT überflüssig.", "id": 405}, {"cat": "Zervixkarzinom & Screening", "q": "Was ist beim Zervixkarzinom Stadium IB mit Fertilität möglich?", "a": "Bei IB1 (≤2cm) und Kinderwunsch: Trachelektomie + pelvine Lymphonodektomie. Bei IB2–IB3: Wertheim-Op oder primäre Radiochemotherapie.", "id": 406}, {"cat": "Zervixkarzinom & Screening", "q": "Was bedeutet ASC-H im Pap-Abstrich?", "a": "Atypical Squamous Cells, cannot exclude HSIL. Höheres Malignitätsrisiko als ASCUS. Management: direkte Kolposkopie (HPV-Triage nicht ausreichend).", "id": 407}, {"cat": "Zervixkarzinom & Screening", "q": "Was ist der jährliche Papanicolaou-Abstrich und um wie viel reduziert er Mortalität?", "a": "Jährlicher Pap reduziert das Risiko an Gebärmutterhalskrebs zu sterben um ~75%. Regelmässiges Screening ist der wichtigste Faktor für Früherkennung.", "id": 408}, {"cat": "Geburtshilfe", "q": "Was ist die Definition des Geburtsbeginns?", "a": "Auftreten regelmässiger, portiowirksamer Wehen (mind. 2/10 min über 1h) mit Portioöffnung. Nicht: erste Kontraktionen, Blasensprung, Zeichnungsblutung, Tiefertreten des Kindsteils.", "id": 409}, {"cat": "Geburtshilfe", "q": "Was ist das Vorgehen bei einem asymptomatischen Myom in der Schwangerschaft?", "a": "Beobachtend. Myome können in der SS wachsen (hormonell stimuliert). Risiken: Fehlgeburt, Frühgeburt, Lageanomalien, Plazentaretention. Keine Op in der SS (ausser Notfall).", "id": 410}, {"cat": "Geburtshilfe", "q": "Was ist das 'rote Degenerat' bei Myomen in der Schwangerschaft?", "a": "Akute Einblutung in das Myom (Carneous Degeneration). Starke Schmerzen, Fieber, lokaler Druckschmerz. Therapie: Analgesie + NSAR (bis 32 SSW), Bettruhe. Spontane Besserung nach Tagen.", "id": 411}, {"cat": "Geburtshilfe", "q": "Was ist die häufigste gynäkologische Notfalldiagnose während der Schwangerschaft (ausser SS-Komplikationen)?", "a": "Ovarialzystentorsion (häufigste) und akute Appendizitis. Appendizitis in SS: atypische Lokalisation (Appendix durch SS verlagert → Schmerz im rechten Mittelbauch). Diagnose: klinisch + Sonographie, MRT.", "id": 412}, {"cat": "Geburtshilfe", "q": "Welche Aussage zu Hepatitis B in der Schwangerschaft ist korrekt?", "a": "Zum Screening reicht HBsAg allein aus. Bei positivem HBsAg: aktive + passive Immunisierung des NG innerhalb 12h. Anti-HBc-IgG positiv (ohne HBsAg) = frühere Immunität.", "id": 413}, {"cat": "Geburtshilfe", "q": "Was ist die Bedeutung von GBS (Streptococcus agalactiae Gruppe B) in der Schwangerschaft?", "a": "GBS bei ~20% der schwangeren Frauen. Risiko: neonatale Early-onset-Sepsis. Screening: Rektalabstrich 35.–37. SSW. Prophylaxe: Penicillin G i.v. intrapartum bei positivem Befund oder Risikofaktoren.", "id": 414}, {"cat": "Geburtshilfe", "q": "Was ist das Risiko bei bekannter mütterlicher CMV-Primärinfektion in der Schwangerschaft?", "a": "Vertikale Transmissionsrate: ~30–40% im 1. Trimenon, bis 70% im 3. Trimenon. Klinisch: Chorioretinitis, Hirnverkalkungen, IUGR, Mikrozephalie, Taubheit. CMV: häufigste kongenitale Virusinfektion.", "id": 415}, {"cat": "Geburtshilfe", "q": "Was ist das Vorgehen bei Parvovirus B19 in der Schwangerschaft?", "a": "Parvovirus B19 (Ringelröteln/Fünfte Krankheit) → aplastische Krise beim Fetus → Hydrops fetalis. Serologische Kontrolle, Doppler der A. cerebri media (Anämie-Screening). Intrauterine Transfusion bei fetaler Anämie.", "id": 416}, {"cat": "Geburtshilfe", "q": "Was ist beim 2-jährigen Bruder eines NG mit Varizellen zu beachten?", "a": "NG vor Varizellen schützen (keine Exposition). Mutter und NG: sofortige Isolation. Immunglobuline an NG geben. Kind als ansteckend betrachten bis alle Bläschen verkrustet sind.", "id": 417}, {"cat": "Geburtshilfe", "q": "Was ist die Abklärung bei einer Schwangeren in der 10. SSW mit positivem Abstrich auf ASC-US?", "a": "HPV-Nachweis veranlassen. Bei HPV+: Kolposkopie (kein ECC!). Keine Konisation in der SS. Biopsie nur bei Verdacht auf Invasion. Reevaluation 6 Wochen post partum.", "id": 418}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was sind typische Befunde beim Turner-Syndrom (45,X0)?", "a": "Kleinwuchs (<150cm), Gonadendysgenesie (Streak Gonads → primäre Amenorrhoe), Pterygium colli, cubitus valgus, Schildbrust, Aortenisthmusstenose (35%), Hufeisenniere. Intelligenz: normal.", "id": 419}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was ist das Klinefelter-Syndrom (47,XXY)?", "a": "Männer mit zusätzlichem X-Chromosom. Klinisch: Hochwuchs, Gynäkomastie, kleine Hoden, Infertilität (Azoospermie). Intelligenz meist normal. Therapie: Testosteron, ICSI mit TESE möglich.", "id": 420}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was ist das Down-Syndrom (Trisomie 21) und welche Herzfehler sind typisch?", "a": "Häufigste chromosomale Anomalie (1:800 Geburten). Herzfehler bei 40–50%: AV-Kanal (häufigste), VSD, ASD. Weitere: mentale Retardierung, Duodenalatresie, Atlantoaxiale Instabilität.", "id": 421}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was ist das Swyer-Syndrom?", "a": "46,XY-Gonadendysgenesie: Phänotyp weiblich, keine Gonaden (Streak), keine Pubertät, primäre Amenorrhoe. Therapie: Gonadektomie (Malignomrisiko), HRT.", "id": 422}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was ist das Androgen-Insensitivitäts-Syndrom (AIS)?", "a": "46,XY-Karyotyp: Androgenrezeptor-Defekt → Phänotyp weiblich. Komplett (CAIS): normale Entwicklung, keine Menarche, keine Pubis-/Axillarbehaarung, kurze blind endende Vagina. Gonaden: testes (Malignitätsrisiko).", "id": 423}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was ist Hypospadie und welche Chromosomenstörung ist assoziiert?", "a": "Urethralmündung an der Unterseite des Penis statt an der Spitze. Meist isoliert, kann bei AGS oder anderen Störungen der Geschlechtsentwicklung auftreten. Operativer Korrektur im Säuglingsalter.", "id": 424}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was ist das MRKH-Syndrom und wie wird es behandelt?", "a": "Vaginalaplasie/-hypoplasie + Uterusaplasie bei 46,XX. Ovarien normal (normale Pubertät). Primäre Amenorrhoe. Therapie: Vaginalerweiterung (Frank-Methode, nicht-operativ bevorzugt) oder Vaginoplastik.", "id": 425}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was ist kongenitale Adrenale Hyperplasie (CAH) beim Mädchen?", "a": "21-Hydroxylase-Mangel: Androgen-Überschuss → Virilisierung der äusseren Genitale (Klitorishypertrophie, Labienfusion). 46,XX-Mädchen wirken phänotypisch als Jungen. Salzverlust in schwerer Form.", "id": 426}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was ist Neuralrohrdefekt (Spina bifida) und wie wird er verhindert?", "a": "Unvollständiger Verschluss des Neuralrohrs. Prävention: Folsäure 0,4–0,8 mg/Tag präkonzeptionell und im 1. Trimenon (hochdosiert 5 mg/Tag bei Epilepsie, Methotrexat, Adipositas).", "id": 427}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was ist der Banana- und Lemon-Sign bei Spina bifida?", "a": "Banana-Sign: Kleinhirn/Cerebellum verformt bananenförmig durch Arnold-Chiari-Malformation (II). Lemon-Sign: Stirnknochen zeigt Eindellung = zitronenförmiger Schädel. Beide auf Frontalschnitt erkennbar.", "id": 428}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was ist die Oesophagusatresie und wie äussert sie sich?", "a": "Unterbrechung des Oesophagus. Meist mit tracheoösophagealer Fistel (85%). Symptom: Polyhydramnion (Fetus kann nicht schlucken), postpartum: Speichelstau, Zyanose beim ersten Fütterungsversuch.", "id": 429}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was ist die Duodenalatresie und womit ist sie assoziiert?", "a": "Stenose/Atresie des Duodenums. 'Double-bubble' im Ultraschall. Assoziiert mit Trisomie 21 (30%), Polyhydramnion. Therapie: chirurgische Korrektur (Duodenoduodenostomie) postpartal.", "id": 430}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was ist die persistierende pulmonale Hypertension des Neugeborenen (PPHN)?", "a": "Anhaltend erhöhter Pulmonalarteriendruck nach Geburt. Rechts-links-Shunt via Foramen ovale/Ductus arteriosus → Hypoxie. Ursachen: MAS, Zwerchfellhernie, Asphyxie. Therapie: NO-Inhalation, Hochfrequenzbeatmung.", "id": 431}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was ist die Retinaopathie des Frühgeborenen (ROP)?", "a": "Abnorme Gefässneubildung der Retina bei Frühgeborenen, verstärkt durch hohe O₂-Gabe. Screening bei <31 SSW oder <1500g. Therapie: Lasertherapie, intravitreales Anti-VEGF.", "id": 432}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was sind Komplikationen des Frühgeborenen nach 34. SSW?", "a": "Hypoglykämie, Hypothermie, Fütterungsprobleme. Nicht: hyaline Membrankrankheit (eher <34 SSW), schwere Apnoen. Monitoring für 24–48h empfohlen.", "id": 433}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was ist der Morbus haemolyticus neonatorum?", "a": "Hämolytische Erkrankung des NG durch maternale Antikörper gegen fetale Erythrozytenantigene (Rh, ABO). Klinisch: Ikterus, Anämie, Hydrops. Therapie: Phototherapie, ggf. Austauschtransfusion.", "id": 434}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was ist der Unterschied zwischen Kephalhämatom und Caput succedaneum?", "a": "Caput succedaneum: Weichteilödem über Einstellungsbereich, überschreitet Schädelnähte, bildet sich schnell zurück. Kephalhämatom: subperiostale Blutung, begrenzt durch Schädelnähte, Wochen bis Rückbildung.", "id": 435}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was ist Subgalealhämatom und warum ist es gefährlich?", "a": "Blutung zwischen Galea aponeurotic und Periost. Überschreitet Schädelnähte, kann grosses Blutvolumen aufnehmen → hämorrhagischer Schock möglich. Häufiger nach Vakuumextraktion.", "id": 436}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was ist das neonatale Abstinenz-Syndrom (NAS)?", "a": "Entzugssymptome des NG nach intrauteriner Opioid-Exposition. Symptome: Zittern, Schlafstörung, schlechtes Trinken, Erbrechen, Hyperthermie, Krampfanfälle. Therapie: Morphin oder Methadon oral.", "id": 437}, {"cat": "Fehlbildungen & Neonatologie", "q": "Was ist das Potter-Syndrom?", "a": "Folge bilateraler Nierenagenese: Oligohydramnion → Lungenhypoplasie, Gesichtsverformungen (Potter-Facies), Klumpfüsse. Letal durch Ateminsuffizienz.", "id": 438}];
export const CATEGORIES = ["Alle Themen", ...[...new Set(CARDS.map(c=>c.cat))].sort()];
